/**
 * Playwright Global Setup
 *
 * Resets test user state before each E2E test run to ensure
 * a clean environment (avoids accumulated state from previous runs).
 */
import { execSync } from 'child_process';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

export default async function globalSetup() {
  const sqlFile = path.resolve(__dirname, '..', '..', 'scripts', 'reset-test-state.sql');
  try {
    execSync(
      `Get-Content "${sqlFile}" | docker exec -i surplus_db psql -U student -d surplus_db`,
      { shell: 'powershell.exe', stdio: 'pipe', timeout: 15_000 }
    );
    console.log('[globalSetup] Test DB state reset successfully');
  } catch (err: any) {
    console.warn('[globalSetup] Failed to reset DB state (tests may still work):', err.message);
  }
}

/* eslint-disable @typescript-eslint/no-explicit-any, prefer-const, @typescript-eslint/no-unused-vars */
import { render } from '@testing-library/react'
import App from '../App'

vi.mock('react-router-dom', () => ({
  BrowserRouter: ({ children }: any) => children,
  Routes: ({ children }: any) => children,
  Route: ({ element }: any) => element,
  Link: ({ to, children }: any) => <a href={to}>{children}</a>,
  Navigate: ({ to }: any) => <div data-testid="navigate" data-to={to} />,
  useNavigate: () => vi.fn(),
  useLocation: () => ({ pathname: '/', state: null }),
  Outlet: () => <div data-testid="outlet" />
}))

vi.mock('../pages/LandingPage', () => ({
  default: () => <div data-testid="landing">Landing Page</div>
}))

vi.mock('../pages/Login', () => ({
  default: () => <div data-testid="login">Login Page</div>
}))

vi.mock('../pages/Register', () => ({
  default: () => <div data-testid="register">Register Page</div>
}))

vi.mock('../layouts/DashboardLayout', () => ({
  default: () => <div data-testid="dashboard-layout">Dashboard</div>
}))

describe('App - Routing Component', () => {
  beforeEach(() => {
    localStorage.clear()
    vi.clearAllMocks()
  })

  it('should render the App component', () => {
    const { container } = render(<App />)
    expect(container).toBeTruthy()
  })

  it('should setup BrowserRouter for navigation', () => {
    const { container } = render(<App />)
    expect(container.querySelector('div')).toBeTruthy()
  })

  it('should define all application routes', () => {
    const { container } = render(<App />)
    const elements = container.querySelectorAll('[data-testid*=""]')
    expect(elements.length >= 0).toBeTruthy()
  })

  it('should render without crashing', () => {
    expect(() => render(<App />)).not.toThrow()
  })
})

/* eslint-disable @typescript-eslint/no-explicit-any, prefer-const, @typescript-eslint/no-unused-vars */
import { render, screen, waitFor } from '@testing-library/react'
import DashboardLayout from '../../layouts/DashboardLayout'
import { getNotifications, getUserProfile } from '../../services/api'

vi.mock('react-router-dom', () => ({
  useNavigate: () => vi.fn(),
  useLocation: () => ({ pathname: '/dashboard' }),
  Link: ({ to, children }: any) => <a href={to}>{children}</a>,
  Outlet: () => <div data-testid="outlet" />,
}))

describe('DashboardLayout - Main Dashboard Structure', () => {
  beforeEach(() => {
    localStorage.clear()
    localStorage.setItem('user', JSON.stringify({
      id: '1',
      name: 'Test User',
      role: 'donor',
      email: 'test@example.com'
    }))
    vi.clearAllMocks()
    vi.mocked(getNotifications).mockResolvedValue([])
    vi.mocked(getUserProfile).mockResolvedValue({} as any)
  })

  it('should render dashboard layout container', () => {
    const { container } = render(<DashboardLayout />)
    expect(container).toBeTruthy()
  })

  it('should display sidebar with navigation links', () => {
    render(<DashboardLayout />)
    const links = screen.getAllByRole('link')
    expect(links.length).toBeGreaterThan(0)
  })

  it('should have outlet for nested dashboard routes', async () => {
    const { container } = render(<DashboardLayout />)
    // Outlet renders after profile is ready
    await waitFor(() => {
      expect(container.querySelector('[data-testid="outlet"]')).toBeTruthy()
    })
  })

  it('should render user name in sidebar', () => {
    render(<DashboardLayout />)
    expect(screen.getByText('Test User')).toBeTruthy()
  })

  it('should render without errors', () => {
    expect(() => render(<DashboardLayout />)).not.toThrow()
  })
})

/* eslint-disable @typescript-eslint/no-explicit-any, prefer-const, @typescript-eslint/no-unused-vars */
import { render } from '@testing-library/react'
import Login from '../../pages/Login'

vi.mock('react-router-dom', () => ({
    useNavigate: () => vi.fn(),
    Link: ({ to, children }: any) => <a href={to}>{children}</a>,
    BrowserRouter: ({ children }: any) => children,
    Routes: ({ children }: any) => children,
    Route: ({ element }: any) => element,
}))

vi.mock('../../services/api', () => ({
    loginUser: vi.fn(),
}))

describe('Login - User Authentication', () => {
    beforeEach(() => {
        localStorage.clear()
        vi.clearAllMocks()
    })

    it('should render login form with email and password fields', () => {
        render(<Login />)
        const emailInputs = document.querySelectorAll('input[type="email"]')
        const passwordInputs = document.querySelectorAll('input[type="password"]')
        expect(emailInputs.length > 0 || passwordInputs.length > 0).toBeTruthy()
    })

    it('should display login page title and branding', () => {
        const { container } = render(<Login />)
