    vi.mocked(adminAPI.getAllDonations).mockResolvedValue({ data: [] } as any);
    vi.mocked(adminAPI.getFlaggedDonations).mockResolvedValue({ data: [] } as any);
    vi.mocked(adminAPI.getAllTickets).mockResolvedValue({ data: [] } as any);
