import { useEffect, useState } from 'react'
import { Link, Outlet, useNavigate, useLocation } from 'react-router-dom'
import { LayoutDashboard, PlusCircle, Map, History, LogOut, Bell, TrendingUp, User, Navigation2, Trophy, LifeBuoy, AlertTriangle, MapPin, Star, Languages, Settings } from 'lucide-react'
import { useTranslation } from 'react-i18next'
import { getNotifications, getUserProfile } from "../services/api";
import { socketService } from "../services/socket";

export default function DashboardLayout() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const location = useLocation()
  const [unreadCount, setUnreadCount] = useState(0)
  const [isRedirecting, setIsRedirecting] = useState(false)
  const [profileReady, setProfileReady] = useState(false)

  const user = JSON.parse(localStorage.getItem('user') || '{}')
  const userRole = (user.role || 'donor').toLowerCase()

  // Refresh profile from backend so isVerified and other fields are up-to-date
  useEffect(() => {
    getUserProfile()
      .catch(() => { })
      .finally(() => setProfileReady(true));
  }, [])

  useEffect(() => {
    // Redirect to role-specific dashboard
    if (location.pathname === '/dashboard') {
      setIsRedirecting(true)
      if (userRole === 'ngo') {
        navigate('/dashboard/ngo', { replace: true })
      } else if (userRole === 'volunteer') {
        navigate('/dashboard/volunteer', { replace: true })
      } else {
        // Donor stays at /dashboard
        setIsRedirecting(false)
      }
    } else {
      // Not on /dashboard, so we're not redirecting
      setIsRedirecting(false)
    }
  }, [userRole, location.pathname, navigate])

  useEffect(() => {
    // Initialize socket connection
    socketService.connect();

    // Load initial notification count
    loadNotifications()

    // Listen for real-time notifications
    const unsubNotif = socketService.onNotification(() => {
      // Backend persists notifications; just bump the count
      setUnreadCount(prev => prev + 1);
    });

    return () => {
      unsubNotif();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  async function loadNotifications() {
    try {
      const notifications = await getNotifications()
      setUnreadCount(notifications.filter(n => !n.read).length)
    } catch (error) {
      console.error('Failed to load notifications:', error)
    }
  }

  const logout = () => {
    localStorage.removeItem('token')
    localStorage.removeItem('user')
    navigate('/login')
  }

  const navLinks = [
    { to: userRole === 'ngo' ? '/dashboard/ngo' : '/dashboard', icon: LayoutDashboard, label: t('dashboard'), roles: ['donor', 'ngo', 'volunteer'] },
    { to: '/dashboard/add', icon: PlusCircle, label: t('addFood'), roles: ['donor'] },
    { to: '/dashboard/map', icon: Map, label: t('discover'), roles: ['donor', 'ngo', 'volunteer'] },
    { to: '/dashboard/location', icon: Navigation2, label: t('liveTracking'), roles: ['volunteer'] },
    { to: '/dashboard/navigation', icon: MapPin, label: t('navigationLabel'), roles: ['ngo', 'volunteer'] },
    { to: '/dashboard/history', icon: History, label: t('history'), roles: ['donor', 'ngo', 'volunteer'] },
    { to: '/dashboard/alerts', icon: AlertTriangle, label: t('nearExpiry'), roles: ['donor', 'ngo', 'volunteer'] },
    { to: '/dashboard/impact', icon: TrendingUp, label: t('impact'), roles: ['donor', 'ngo', 'volunteer'] },
    { to: '/dashboard/leaderboard', icon: Trophy, label: t('leaderboards'), roles: ['donor', 'ngo', 'volunteer'] },
    { to: '/dashboard/feedback', icon: Star, label: t('ratings'), roles: ['donor', 'ngo'] },
    { to: '/dashboard/support', icon: LifeBuoy, label: t('support'), roles: ['donor', 'ngo', 'volunteer'] },
  ].filter(link => link.roles.includes(userRole))

  const isActive = (path: string) => {
    if (path === '/dashboard') {
      return location.pathname === path
    }
    return location.pathname.startsWith(path)
  }

  const getRoleColor = () => {
    const colors = {
      donor: 'from-emerald-500 to-emerald-600',
      ngo: 'from-blue-500 to-blue-600',
      volunteer: 'from-purple-500 to-purple-600'
    }
    return colors[userRole as keyof typeof colors] || 'from-emerald-500 to-emerald-600'
  }

  const getRoleLabel = () => {
    const labels: Record<string, string> = {
      donor: t('donor'),
      ngo: t('ngo'),
      volunteer: t('volunteer')
    }
    return labels[userRole] || t('user')
  }

  return (
    <div className="min-h-screen flex bg-gray-50 dark:bg-slate-950">
      {/* Sidebar */}
      <aside className="sidebar flex flex-col">
        {/* Logo */}
        <div className="sidebar-header">
          <div className="flex items-center gap-3">
            <div className="logo-icon">
              <span className="text-white font-bold text-xl">S</span>
            </div>
            <div>
              <h1 className="text-xl font-bold text-gray-900 dark:text-white tracking-tight">
                Surplus<span className="text-emerald-400">Sync</span>
              </h1>
            </div>
          </div>
        </div>

        {/* User Info */}
        <div className="p-4 border-b border-gray-200 dark:border-slate-800">
          <div className="flex items-center gap-3 p-3 rounded-xl bg-white/80 dark:bg-slate-900/50 border border-gray-200 dark:border-slate-800">
            <div className={`w-10 h-10 rounded-full bg-gradient-to-br ${getRoleColor()} flex items-center justify-center text-sm font-bold text-white shadow-lg`}>
              {user.name?.[0]?.toUpperCase() || 'U'}
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-sm font-semibold text-gray-900 dark:text-white truncate">
                {user.organizationName || user.name || 'User'}
              </p>
              <p className="text-xs text-gray-500 dark:text-slate-500">{getRoleLabel()}</p>
            </div>
            {user.verified && (
              <div className="w-5 h-5 rounded-full bg-emerald-500 flex items-center justify-center">
                <span className="text-white text-xs">✓</span>
              </div>
            )}
          </div>
        </div>

        {/* Navigation */}
        <nav className="flex-1 p-3 space-y-1">
          {navLinks.map((link) => (
            <Link
              key={link.to}
              to={link.to}
              className={`nav-item ${isActive(link.to) ? 'nav-item-active' : 'nav-item-inactive'
                }`}
            >
              <link.icon className="w-5 h-5" />
              <span>{link.label}</span>
            </Link>
          ))}
        </nav>

        {/* Bottom Actions */}
        <div className="p-3 border-t border-gray-200 dark:border-slate-800 space-y-1">
          <Link
            to="/dashboard/notifications"
            className={`nav-item relative ${isActive('/dashboard/notifications') ? 'nav-item-active' : 'nav-item-inactive'
              }`}
          >
            <Bell className="w-5 h-5" />
            <span>{t('notifications')}</span>
            {unreadCount > 0 && (
              <span className="notification-badge">
                {unreadCount > 9 ? '9+' : unreadCount}
              </span>
            )}
          </Link>

          <Link
            to="/dashboard/profile"
            className={`nav-item ${isActive('/dashboard/profile') ? 'nav-item-active' : 'nav-item-inactive'
              }`}
          >
            <User className="w-5 h-5" />
            <span>{t('profile')}</span>
          </Link>

          <Link
            to="/dashboard/accessibility"
            className={`nav-item ${isActive('/dashboard/accessibility') ? 'nav-item-active' : 'nav-item-inactive'
              }`}
          >
            <Languages className="w-5 h-5" />
            <span>{t('accessibilitySettings')}</span>
          </Link>

          <Link
            to="/dashboard/preferences"
            className={`nav-item ${isActive('/dashboard/preferences') ? 'nav-item-active' : 'nav-item-inactive'
              }`}
          >
            <Settings className="w-5 h-5" />
            <span>{t('preferences')}</span>
          </Link>

          <button
            onClick={logout}
            className="nav-item nav-item-inactive w-full text-left"
          >
            <LogOut className="w-5 h-5" />
            <span>{t('signOut')}</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="main-content p-8">
        <div className="max-w-7xl mx-auto">
          {isRedirecting || !profileReady ? (
            <div className="flex items-center justify-center h-screen">
              <div className="text-center">
                <div className="w-12 h-12 rounded-full bg-gradient-to-br from-emerald-500 to-emerald-600 animate-pulse mx-auto mb-4"></div>
                <p className="text-gray-500 dark:text-slate-400">Loading...</p>
              </div>
            </div>
          ) : (
            <Outlet />
          )}
        </div>
      </main>
    </div>
  )
}

import { useState, useEffect } from 'react'
import { useTranslation } from 'react-i18next'
import { MapContainer, TileLayer, Marker, Popup } from 'react-leaflet'
import L from 'leaflet'
import 'leaflet/dist/leaflet.css'
import { getDonations, claimDonation, updateDonationStatus, type Donation } from '../../services/api'
import { socketService } from '../../services/socket'
import { Clock, Shield, AlertTriangle, X, Image as ImageIcon, MapPin, CheckCircle2, ChevronLeft, ChevronRight } from 'lucide-react'
import { toast } from 'sonner'

// Fix for default marker icons
// eslint-disable-next-line @typescript-eslint/no-explicit-any
delete (L.Icon.Default.prototype as any)._getIconUrl
L.Icon.Default.mergeOptions({
    iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon-2x.png',
    iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon.png',
    shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png',
})

const createIcon = (color: string) => new L.DivIcon({
    className: 'custom-marker',
    html: `<div style="width:14px;height:14px;background:${color};border-radius:50%;border:2px solid white;box-shadow:0 2px 6px rgba(0,0,0,0.3);"></div>`,
    iconSize: [14, 14],
    iconAnchor: [7, 7],
    popupAnchor: [0, -10],
})

const activeIcon = createIcon('#10b981')
const claimedIcon = createIcon('#f59e0b')
const urgentIcon = createIcon('#ef4444')

export default function DiscoveryMap() {
    const { t } = useTranslation()
    const [filter, setFilter] = useState<'all' | 'AVAILABLE' | 'CLAIMED'>('all')
    const [donations, setDonations] = useState<Donation[]>([])
    const [loading, setLoading] = useState(true)
    const [claiming, setClaiming] = useState<string | null>(null)
    const [processingId, setProcessingId] = useState<string | null>(null)
    const [selectedDonation, setSelectedDonation] = useState<Donation | null>(null) // 🔍 State for Modal
    const [currentImageIndex, setCurrentImageIndex] = useState(0)

    const user = JSON.parse(localStorage.getItem('user') || '{}')
    const userRole = (user.role || 'donor').toLowerCase()
    const isVerified = user.isVerified === true
    const canClaim = (userRole === 'ngo' && isVerified) || userRole === 'volunteer'

    useEffect(() => {
        loadDonations()

        // Listen for new donations (socket is managed by DashboardLayout)
        const unsubscribeCreated = socketService.onDonationCreated((data) => {
            toast.success(`🍕 ${t('newFoodAlert')}: ${data.foodType}!`, {
                description: `${data.name} - ${data.location.address}`,
                duration: 5000,
            })
            // Re-fetch donations to show the new pin
            loadDonations()
        })

        // Listen for claimed donations
        const unsubscribeClaimed = socketService.onDonationClaimed((data) => {
            toast.info(`🔔 ${t('foodClaimedAlert')}`, {
                description: `${data.donationId} has been claimed`,
                duration: 3000,
            })
            // Remove the claimed donation from state
            setDonations((prevDonations) =>
                prevDonations.filter((donation) => donation.id !== data.donationId)
            )
            // Close modal if it was for this donation
            if (selectedDonation?.id === data.donationId) {
                setSelectedDonation(null)
                setCurrentImageIndex(0)
            }
        })

        return () => {
            unsubscribeCreated()
            unsubscribeClaimed()
        }
    }, [])

    const loadDonations = async () => {
        setLoading(true)
        try {
            const data = await getDonations()
            setDonations(data)
        } finally {
            setLoading(false)
        }
    }

    const handleClaim = async (donationId: string) => {
        if (!canClaim) return

        setClaiming(donationId)
        try {
            await claimDonation(donationId)
            await loadDonations()
            setSelectedDonation(null) // Close modal on success
            setCurrentImageIndex(0)
        } catch (err: unknown) {
            const error = err as { response?: { data?: { message?: string } }, message?: string };
            const msg =
                error?.response?.data?.message ||
                error?.message ||
                'Failed to claim donation'
            toast.error('Unable to claim', { description: msg })
        } finally {
            setClaiming(null)
        }
    }

    const handleConfirmPickup = async (donationId: string) => {
        if (processingId) return
        setProcessingId(donationId)
        try {
            await updateDonationStatus(donationId, 'PICKED_UP')
            await loadDonations()
            setSelectedDonation(null)
            setCurrentImageIndex(0)
        } catch (err: unknown) {
            const error = err as { message?: string };
            alert(error.message || 'Failed to confirm pickup')
        } finally {
            setProcessingId(null)
        }
    }

    const handleConfirmDelivery = async (donationId: string) => {
        if (processingId) return
        setProcessingId(donationId)
        try {
            await updateDonationStatus(donationId, 'DELIVERED')
            await loadDonations()
            setSelectedDonation(null)
            setCurrentImageIndex(0)
        } catch (err: unknown) {
            const error = err as { message?: string };
            alert(error.message || 'Failed to confirm delivery')
        } finally {
            setProcessingId(null)
        }
    }

    // Filter out expired donations from the map
    const nonExpired = donations.filter(d => {
        if (d.status === 'EXPIRED') return false
        if (d.expiryTime && new Date(d.expiryTime).getTime() < Date.now()) return false
        return true
    })
    const filtered = filter === 'all'
        ? nonExpired
        : nonExpired.filter(d => d.status === filter)

    const getTimeRemaining = (expiryTime: Date) => {
        const now = new Date()
        const remaining = new Date(expiryTime).getTime() - now.getTime()
        if (remaining <= 0) return { text: 'Expired', urgent: true, expired: true }
        const hours = Math.floor(remaining / (1000 * 60 * 60))
        const minutes = Math.floor((remaining % (1000 * 60 * 60)) / (1000 * 60))

        if (hours < 1) return { text: `${minutes}m`, urgent: true, expired: false }
        if (hours < 3) return { text: `${hours}h ${minutes}m`, urgent: true, expired: false }
        return { text: `${hours}h`, urgent: false, expired: false }
    }

    const getMarkerIcon = (donation: Donation) => {
        if (donation.status === 'CLAIMED') return claimedIcon
        if (donation.status === 'AVAILABLE') {
            const timeRemaining = getTimeRemaining(donation.expiryTime)
            if (timeRemaining.urgent) return urgentIcon
        }
        return activeIcon
    }

    return (
        <div className="h-[calc(100vh-4rem)] flex flex-col -m-8 relative">
            {/* Header */}
            <div className="p-4 border-b border-gray-200 dark:border-slate-800 bg-gray-50 dark:bg-slate-950">
                <div className="flex items-center justify-between mb-3">
                    <h1 className="text-lg font-semibold text-gray-900 dark:text-white">{t('discoveryMapTitle')}</h1>
                    <div className="flex gap-2">
                        {(['all', 'AVAILABLE', 'CLAIMED'] as const).map((f) => (
                            <button
                                key={f}
                                onClick={() => setFilter(f)}
                                className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-colors capitalize ${filter === f
                                        ? 'bg-emerald-500 text-white'
                                        : 'bg-gray-100 dark:bg-slate-800 text-gray-500 dark:text-slate-400 hover:text-gray-900 dark:hover:text-white'
                                    }`}
                            >
                                {f === 'AVAILABLE' ? t('available') : f === 'CLAIMED' ? t('claimed') : t('all')}
                            </button>
                        ))}
                    </div>
                </div>
            </div>

            {/* Map */}
            <div className="flex-1 relative z-0">
                {loading ? (
                    <div className="absolute inset-0 flex items-center justify-center bg-gray-50 dark:bg-slate-950">
                        <p className="text-gray-500 dark:text-slate-500">{t('loadingDonations')}</p>
                    </div>
                ) : (
                    <MapContainer
                        center={[28.6139, 77.2090]}
                        zoom={13}
                        style={{ height: '100%', width: '100%' }}
                    >
                        <TileLayer
                            attribution='&copy; OpenStreetMap'
                            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                        />

                        {filtered.map((donation) => (
                            <Marker
                                key={donation.id}
                                position={[donation.location.lat, donation.location.lng]}
                                icon={getMarkerIcon(donation)}
                            >
                                <Popup>
                                    <div className="p-2 min-w-[200px]">
                                        <div className="mb-2">
                                            <p className="font-semibold text-gray-900 dark:text-white mb-0.5">{donation.name}</p>
                                            <p className="text-xs text-gray-500 dark:text-slate-400">{donation.quantity} {donation.unit} • {donation.foodType}</p>
                                        </div>

                                        {/* Status Badge */}
                                        <div className="mb-3 flex items-center gap-2">
                                            <span className={`inline-block px-2 py-0.5 rounded text-[10px] font-medium capitalize ${donation.status === 'AVAILABLE'
                                                    ? 'bg-emerald-500/20 text-emerald-400'
                                                    : 'bg-amber-500/20 text-amber-400'
                                                }`}>
                                                {donation.status === 'AVAILABLE' ? t('available') : donation.status.toLowerCase()}
                                            </span>
                                            {donation.status === 'AVAILABLE' && (
                                                <span className={`text-[10px] font-medium ${getTimeRemaining(donation.expiryTime).urgent ? 'text-red-400' : 'text-emerald-400'
                                                    }`}>
                                                    {getTimeRemaining(donation.expiryTime).text} {t('left')}
                                                </span>
                                            )}
                                        </div>

                                        {/* View Details Button - Triggers Modal */}
                                        <button
                                            onClick={() => setSelectedDonation(donation)}
                                            className="w-full py-1.5 bg-gray-100 dark:bg-slate-800 hover:bg-gray-200 dark:hover:bg-gray-200 dark:bg-slate-700 text-gray-800 dark:text-slate-200 text-xs rounded font-medium transition-colors border border-gray-300 dark:border-slate-700"
                                        >
                                            {t('viewDetailsImage')}
                                        </button>
                                    </div>
                                </Popup>
                            </Marker>
                        ))}
                    </MapContainer>
                )}
            </div>

            {/* 🔍 DETAIL MODAL */}
            {selectedDonation && (
                <div className="fixed inset-0 z-[2000] flex items-center justify-center p-4 bg-black/30 dark:bg-slate-950/80 backdrop-blur-sm">
                    <div className="bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-xl w-full max-w-2xl max-h-[90vh] overflow-y-auto shadow-2xl flex flex-col md:flex-row">

                        {/* LEFT: Image Section */}
                        <div className="w-full md:w-1/2 bg-gray-50 dark:bg-slate-950 h-64 md:h-auto relative group">
                            {selectedDonation.imageUrls && selectedDonation.imageUrls.length > 0 ? (
                                <>
                                    <img
                                        src={selectedDonation.imageUrls[currentImageIndex]}
                                        alt={selectedDonation.name}
                                        className="w-full h-full object-cover"
                                    />
                                    {/* Image Counter */}
                                    <div className="absolute bottom-4 right-4 bg-black/60 text-gray-900 dark:text-white text-xs px-3 py-1 rounded-full">
                                        {currentImageIndex + 1} / {selectedDonation.imageUrls.length}
                                    </div>
                                    {/* Navigation Buttons */}
                                    {selectedDonation.imageUrls.length > 1 && (
                                        <>
                                            <button
                                                onClick={() => setCurrentImageIndex((prev) => (prev - 1 + selectedDonation.imageUrls.length) % selectedDonation.imageUrls.length)}
                                                className="absolute left-4 top-1/2 transform -translate-y-1/2 bg-black/50 hover:bg-black/70 text-gray-900 dark:text-white p-2 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"
                                            >
                                                <ChevronLeft className="w-5 h-5" />
                                            </button>
                                            <button
                                                onClick={() => setCurrentImageIndex((prev) => (prev + 1) % selectedDonation.imageUrls.length)}
                                                className="absolute right-4 top-1/2 transform -translate-y-1/2 bg-black/50 hover:bg-black/70 text-gray-900 dark:text-white p-2 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"
                                            >
                                                <ChevronRight className="w-5 h-5" />
                                            </button>
                                        </>
                                    )}
                                </>
                            ) : (
                                <div className="w-full h-full flex flex-col items-center justify-center text-gray-400 dark:text-slate-600">
                                    <ImageIcon className="w-12 h-12 mb-2 opacity-50" />
                                    <span className="text-sm">{t('noImageUploaded')}</span>
                                </div>
                            )}

                            {/* Urgent Badge Overlay */}
                            {selectedDonation.status === 'AVAILABLE' && getTimeRemaining(selectedDonation.expiryTime).urgent && (
                                <div className="absolute top-4 left-4 bg-red-500 text-white text-xs px-2 py-1 rounded-md font-medium flex items-center gap-1 shadow-lg">
                                    <AlertTriangle className="w-3 h-3" />
                                    {t('urgentExpiringSoon')}
                                </div>
                            )}
                        </div>

                        {/* RIGHT: Details Section */}
                        <div className="w-full md:w-1/2 p-6 flex flex-col">
                            <div className="flex justify-between items-start mb-4">
                                <div>
                                    <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-1">{selectedDonation.name}</h2>
                                    <p className="text-emerald-400 font-medium">{selectedDonation.quantity} {selectedDonation.unit} • {selectedDonation.foodType}</p>
                                </div>
                                <button onClick={() => { setSelectedDonation(null); setCurrentImageIndex(0); }} className="p-1 hover:bg-gray-100 dark:hover:bg-gray-100 dark:bg-slate-800 rounded-full text-gray-500 dark:text-slate-400 transition-colors">
                                    <X className="w-5 h-5" />
                                </button>
                            </div>

                            <div className="space-y-4 flex-1">
                                {/* Donor Info */}
                                <div className="p-3 bg-gray-100/80 dark:bg-slate-800/50 rounded-lg border border-gray-200 dark:border-slate-800">
                                    <p className="text-xs text-gray-500 dark:text-slate-400 uppercase tracking-wider mb-1">{t('donor')}</p>
                                    <div className="flex justify-between items-center">
                                        <span className="text-gray-900 dark:text-white font-medium">{selectedDonation.donorName}</span>
                                        <div className="flex items-center gap-1.5 bg-emerald-500/10 px-2 py-0.5 rounded text-emerald-400 text-xs">
                                            <Shield className="w-3 h-3" />
                                            <span>Trust: {selectedDonation.donorTrustScore.toFixed(1)}</span>
                                        </div>
                                    </div>
                                </div>

                                {/* Description */}
                                {selectedDonation.description && (
                                    <div>
                                        <p className="text-xs text-gray-500 dark:text-slate-400 mb-1">{t('description')}</p>
                                        <p className="text-sm text-gray-700 dark:text-slate-300 leading-relaxed">{selectedDonation.description}</p>
                                    </div>
                                )}

                                {/* Hygiene */}
                                <div>
                                    <p className="text-xs text-gray-500 dark:text-slate-400 mb-2">{t('safetyCheck')}</p>
                                    <div className="flex gap-2">
                                        {selectedDonation.hygiene.keptCovered ? (
                                            <span className="flex items-center gap-1 text-xs bg-emerald-500/10 text-emerald-400 px-2 py-1 rounded border border-emerald-500/20">
                                                <CheckCircle2 className="w-3 h-3" /> {t('keptCovered')}
                                            </span>
                                        ) : (
                                            <span className="flex items-center gap-1 text-xs bg-red-500/10 text-red-400 px-2 py-1 rounded border border-red-500/20">
                                                <X className="w-3 h-3" /> {t('notCovered')}
                                            </span>
                                        )}
                                        {selectedDonation.hygiene.containerClean ? (
                                            <span className="flex items-center gap-1 text-xs bg-emerald-500/10 text-emerald-400 px-2 py-1 rounded border border-emerald-500/20">
                                                <CheckCircle2 className="w-3 h-3" /> {t('cleanContainer')}
                                            </span>
                                        ) : (
                                            <span className="flex items-center gap-1 text-xs bg-red-500/10 text-red-400 px-2 py-1 rounded border border-red-500/20">
                                                <X className="w-3 h-3" /> {t('dirtyContainer')}
                                            </span>
                                        )}
                                    </div>
                                </div>

                                {/* Time */}
                                <div className="flex items-center gap-2 text-sm text-gray-500 dark:text-slate-400">
                                    <Clock className="w-4 h-4" />
                                    <span>{t('prepared', { time: new Date(selectedDonation.preparationTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) })}</span>
                                </div>
                            </div>

                            {/* Action Button */}
                            <div className="mt-6 pt-4 border-t border-gray-200 dark:border-slate-800">
                                {selectedDonation.status === 'AVAILABLE' ? (
                                    canClaim ? (
                                        <button
                                            onClick={() => handleClaim(selectedDonation.id)}
                                            disabled={claiming === selectedDonation.id}
                                            className="w-full py-3 bg-emerald-500 hover:bg-emerald-400 disabled:bg-gray-200 dark:bg-slate-700 text-white rounded-lg font-semibold transition-all shadow-lg shadow-emerald-500/20 flex items-center justify-center gap-2"
                                        >
                                            {claiming === selectedDonation.id ? (
                                                <>{t('claiming')}</>
                                            ) : (
                                                <>
                                                    <MapPin className="w-4 h-4" />
                                                    {t('claimThisFood')}
                                                </>
                                            )}
                                        </button>
                                    ) : userRole === 'ngo' && !isVerified ? (
                                        <div className="text-center p-3 bg-amber-500/10 text-amber-400 rounded-lg text-sm font-medium border border-amber-500/20">
                                            ⏳ {t('verificationPending')} — Cannot claim until verified.
                                        </div>
                                    ) : (
                                        <div className="text-center p-3 bg-gray-100 dark:bg-slate-800 rounded-lg text-gray-500 dark:text-slate-400 text-sm">
                                            {t('loginAsNGO')}
                                        </div>
                                    )
                                ) : (
                                    // If already claimed, show volunteer actions when appropriate
                                    <div>
                                        {userRole === 'volunteer' && selectedDonation.status === 'CLAIMED' ? (
                                            <button
                                                onClick={() => handleConfirmPickup(selectedDonation.id)}
                                                disabled={processingId === selectedDonation.id}
                                                className="w-full py-3 bg-emerald-500 hover:bg-emerald-400 text-white rounded-lg font-semibold transition-all"
                                            >
                                                {processingId === selectedDonation.id ? t('processing') : t('confirmPickup')}
                                            </button>
                                        ) : userRole === 'volunteer' && selectedDonation.status === 'PICKED_UP' ? (
                                            <button
                                                onClick={() => handleConfirmDelivery(selectedDonation.id)}
                                                disabled={processingId === selectedDonation.id}
                                                className="w-full py-3 bg-emerald-500 hover:bg-emerald-400 text-white rounded-lg font-semibold transition-all"
                                            >
                                                {processingId === selectedDonation.id ? t('processing') : t('confirmDelivery')}
                                            </button>
                                        ) : (
                                            <div className="text-center p-3 bg-amber-500/10 text-amber-400 rounded-lg font-medium border border-amber-500/20">{t('alreadyClaimedLabel')}</div>
                                        )}
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    )
}

import { useEffect, useState } from 'react'
import { Link } from 'react-router-dom'
import { useTranslation } from 'react-i18next'
import { getDonations, type Donation } from '../../services/api'
import { socketService } from '../../services/socket'
import { PlusCircle, Map, Clock, TrendingUp, AlertTriangle, X, Image as ImageIcon, Shield, CheckCircle2, ChevronLeft, ChevronRight } from 'lucide-react'

export default function DonorHome() {
  const { t } = useTranslation()
  const [donations, setDonations] = useState<Donation[]>([])
  const [loading, setLoading] = useState(false)
  const [selectedDonation, setSelectedDonation] = useState<Donation | null>(null)
  const [currentImageIndex, setCurrentImageIndex] = useState(0)

  const user = JSON.parse(localStorage.getItem('user') || '{}')

  const load = async () => {
    setLoading(true)
    try {
      const data = await getDonations({ 
        role: 'donor',
        userId: user.id 
      })
      setDonations(data)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    load()

    const unsubscribeCreated = socketService.onDonationCreated(() => {
      load()
    })

    const unsubscribeClaimed = socketService.onDonationClaimed(() => {
      load()
    })

    return () => {
      unsubscribeCreated()
      unsubscribeClaimed()
    }
  }, [])

  const activeCount = donations.filter((d) => d.status === 'AVAILABLE').length
  const claimedCount = donations.filter((d) => d.status === 'CLAIMED').length
  const deliveredCount = donations.filter((d) => d.status === 'DELIVERED').length

  const getTimeRemaining = (expiryTime: Date) => {
    const now = new Date()
    const remaining = new Date(expiryTime).getTime() - now.getTime()
    if (remaining <= 0) return { hours: 0, minutes: 0, urgent: true, expired: true }
    const hours = Math.floor(remaining / (1000 * 60 * 60))
    const minutes = Math.floor((remaining % (1000 * 60 * 60)) / (1000 * 60))
    return { hours, minutes, urgent: hours < 3, expired: false }
  }

  const urgentDonations = donations.filter(d => {
    if (d.status !== 'AVAILABLE') return false
    const time = getTimeRemaining(d.expiryTime)
    return time.urgent && !time.expired
  })

  const getStatusStyle = (status: string) => {
    const styles: Record<string, string> = {
      AVAILABLE: 'bg-emerald-500/10 text-emerald-400',
      CLAIMED: 'bg-amber-500/10 text-amber-400',
      DELIVERED: 'bg-slate-500/10 text-gray-500 dark:text-slate-400',
      EXPIRED: 'bg-red-500/10 text-red-400',
    }
    return styles[status] || styles.AVAILABLE
  }

  const getGreeting = () => {
    const hour = new Date().getHours()
    if (hour < 12) return t('goodMorning')
    if (hour < 18) return t('goodAfternoon')
    return t('goodEvening')
  }

  return (
    <div>
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-2xl font-semibold text-gray-900 dark:text-white">
          {getGreeting()}, {user.name?.split(' ')[0] || 'there'}!
        </h1>
        <p className="text-gray-500 dark:text-slate-500 mt-1">
          {t('manageDonations')}
        </p>
      </div>

      {/* Urgent Alerts */}
      {urgentDonations.length > 0 && (
        <div className="mb-6 p-4 bg-red-500/10 border border-red-500/20 rounded-xl">
          <div className="flex items-start gap-3">
            <AlertTriangle className="w-5 h-5 text-red-400 flex-shrink-0 mt-0.5" />
            <div>
              <p className="text-sm font-medium text-red-400 mb-1">{t('urgentExpiring')}</p>
              <p className="text-xs text-gray-500 dark:text-slate-400">
                You have {urgentDonations.length} donation{urgentDonations.length > 1 ? 's' : ''} expiring within 3 hours
              </p>
            </div>
          </div>
        </div>
      )}

      {/* Status Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
        <div className="rounded-xl border border-emerald-500/20 bg-emerald-500/10 p-5">
          <div className="flex items-center justify-between mb-3">
            <span className="text-xl text-emerald-400">●</span>
            <span className="text-xs font-medium px-2 py-0.5 rounded bg-emerald-500/10 text-emerald-400 uppercase">
              {t('active')}
            </span>
          </div>
          <p className="text-sm text-gray-500 dark:text-slate-400 mb-1">{t('yourListings')}</p>
          <p className="text-3xl font-semibold text-emerald-400">{activeCount}</p>
          {urgentDonations.length > 0 && (
            <p className="text-xs text-red-400 mt-2">
              {t('expiringSoon', { count: urgentDonations.length })}
            </p>
          )}
        </div>

        <div className="rounded-xl border border-amber-500/20 bg-amber-500/10 p-5">
          <div className="flex items-center justify-between mb-3">
            <span className="text-xl text-amber-400">◷</span>
            <span className="text-xs font-medium px-2 py-0.5 rounded bg-amber-500/10 text-amber-400 uppercase">
              {t('inTransit')}
            </span>
          </div>
          <p className="text-sm text-gray-500 dark:text-slate-400 mb-1">{t('pendingPickup')}</p>
          <p className="text-3xl font-semibold text-amber-400">{claimedCount}</p>
        </div>

        <div className="rounded-xl border border-gray-300 dark:border-slate-700 bg-gray-100/50 dark:bg-slate-800/30 p-5">
          <div className="flex items-center justify-between mb-3">
            <span className="text-xl text-gray-500 dark:text-slate-400">✓</span>
            <span className="text-xs font-medium px-2 py-0.5 rounded bg-slate-500/10 text-gray-500 dark:text-slate-400 uppercase">
              {t('complete')}
            </span>
          </div>
          <p className="text-sm text-gray-500 dark:text-slate-400 mb-1">{t('delivered')}</p>
          <p className="text-3xl font-semibold text-gray-500 dark:text-slate-400">{deliveredCount}</p>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
        <Link
          to="/dashboard/map"
          className="group p-6 rounded-xl bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 hover:border-gray-300 dark:hover:border-gray-300 dark:border-slate-700 transition-all"
        >
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 rounded-xl bg-gray-100 dark:bg-slate-800 flex items-center justify-center text-gray-500 dark:text-slate-400 group-hover:text-gray-900 dark:group-hover:text-white transition-colors">
              <Map className="w-6 h-6" />
            </div>
            <div>
              <h3 className="font-semibold text-gray-900 dark:text-white mb-1">{t('discoveryMap')}</h3>
              <p className="text-sm text-gray-500 dark:text-slate-400">
                {t('viewDonationsOnMap')}
              </p>
            </div>
          </div>
        </Link>

        <Link
          to="/dashboard/impact"
          className="group p-6 rounded-xl bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 hover:border-gray-300 dark:hover:border-gray-300 dark:border-slate-700 transition-all"
        >
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 rounded-xl bg-gray-100 dark:bg-slate-800 flex items-center justify-center text-gray-500 dark:text-slate-400 group-hover:text-gray-900 dark:group-hover:text-white transition-colors">
              <TrendingUp className="w-6 h-6" />
            </div>
            <div>
              <h3 className="font-semibold text-gray-900 dark:text-white mb-1">{t('yourImpact')}</h3>
              <p className="text-sm text-gray-500 dark:text-slate-400">{t('seeDifference')}</p>
            </div>
          </div>
        </Link>
      </div>

      {/* Recent Activity */}
      <div className="bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-xl overflow-hidden">
        <div className="p-5 border-b border-gray-200 dark:border-slate-800 flex items-center justify-between">
          <h2 className="font-medium text-gray-900 dark:text-white">
            {t('recentDonations')}
          </h2>
          <Link to="/dashboard/history" className="text-sm text-emerald-400 hover:text-emerald-300">
            {t('viewAll')}
          </Link>
        </div>

        {loading && (
          <div className="p-8 text-center text-gray-500 dark:text-slate-500">{t('loading')}</div>
        )}

        {!loading && donations.length === 0 && (
          <div className="p-8 text-center">
            <p className="text-gray-500 dark:text-slate-500 mb-4">
              {t('noDonationsYet')}
            </p>
            <Link
              to="/dashboard/add"
              className="inline-flex items-center gap-2 px-4 py-2 bg-emerald-500 hover:bg-emerald-400 text-white rounded-lg text-sm font-medium transition-colors"
            >
              <PlusCircle className="w-4 h-4" />
              {t('addFirstDonation')}
            </Link>
          </div>
        )}

        <div className="divide-y divide-gray-200 dark:divide-slate-800">
          {donations.slice(0, 5).map((donation) => {
            const timeLeft = getTimeRemaining(donation.expiryTime)
            return (
              <div key={donation.id} className="p-4 hover:bg-gray-100/50 dark:bg-slate-800/30 transition-colors">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-4 flex-1">
                    <div className={`w-12 h-12 rounded-lg flex items-center justify-center text-2xl ${
                      donation.status === 'AVAILABLE' ? 'bg-emerald-500/10' : 
                      donation.status === 'CLAIMED' ? 'bg-amber-500/10' : 'bg-gray-100 dark:bg-slate-800'
                    }`}>
                      {donation.foodType === 'cooked' && '🍛'}
                      {donation.foodType === 'raw' && '🥬'}
                      {donation.foodType === 'packaged' && '📦'}
                      {donation.foodType === 'fruits' && '🍎'}
                      {donation.foodType === 'bakery' && '🥖'}
                      {donation.foodType === 'dairy' && '🥛'}
                    </div>
                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-1">
                        <p className="font-medium text-gray-900 dark:text-white">{donation.name}</p>
                        {donation.status === 'AVAILABLE' && timeLeft.urgent && !timeLeft.expired && (
                          <span className="text-xs px-1.5 py-0.5 bg-red-500/10 text-red-400 rounded flex items-center gap-1">
                            <Clock className="w-3 h-3" />
                            {timeLeft.hours}h {timeLeft.minutes}m
                          </span>
                        )}
                      </div>
                      <p className="text-sm text-gray-500 dark:text-slate-500">
                        {donation.quantity} {donation.unit}
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <button
                      onClick={() => setSelectedDonation(donation)}
                      className="px-3 py-1 rounded-md text-xs font-medium bg-gray-100 dark:bg-slate-800 text-gray-700 dark:text-slate-300 hover:bg-gray-200 dark:hover:bg-gray-200 dark:bg-slate-700 transition-colors border border-gray-300 dark:border-slate-700"
                    >
                      {t('viewDetails')}
                    </button>
                    <span className={`px-3 py-1 rounded-md text-xs font-medium whitespace-nowrap ${getStatusStyle(donation.status)}`}>
                      {donation.status === 'AVAILABLE' ? t('available') : donation.status}
                    </span>
