              </div>
            )
          })}
        </div>
      </div>

      {/* Detail Modal */}
      {selectedDonation && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center p-4 bg-black/30 dark:bg-slate-950/80 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-xl w-full max-w-2xl max-h-[90vh] overflow-y-auto shadow-2xl flex flex-col md:flex-row">
            
            {/* LEFT: Image Section */}
            <div className="w-full md:w-1/2 bg-gray-50 dark:bg-slate-950 h-64 md:h-auto relative group">
              {selectedDonation.imageUrls && selectedDonation.imageUrls.length > 0 ? (
                <>
                  <img 
                    src={selectedDonation.imageUrls[currentImageIndex]} 
                    alt={selectedDonation.name} 
                    className="w-full h-full object-cover"
                  />
                  {/* Image Counter */}
                  <div className="absolute bottom-4 right-4 bg-black/60 text-gray-900 dark:text-white text-xs px-3 py-1 rounded-full">
                    {currentImageIndex + 1} / {selectedDonation.imageUrls.length}
                  </div>
                  {/* Navigation Buttons */}
                  {selectedDonation.imageUrls.length > 1 && (
                    <>
                      <button
                        onClick={() => setCurrentImageIndex((prev) => (prev - 1 + selectedDonation.imageUrls.length) % selectedDonation.imageUrls.length)}
                        className="absolute left-4 top-1/2 transform -translate-y-1/2 bg-black/50 hover:bg-black/70 text-gray-900 dark:text-white p-2 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"
                      >
                        <ChevronLeft className="w-5 h-5" />
                      </button>
                      <button
                        onClick={() => setCurrentImageIndex((prev) => (prev + 1) % selectedDonation.imageUrls.length)}
                        className="absolute right-4 top-1/2 transform -translate-y-1/2 bg-black/50 hover:bg-black/70 text-gray-900 dark:text-white p-2 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"
                      >
                        <ChevronRight className="w-5 h-5" />
                      </button>
                    </>
                  )}
                </>
              ) : (
                <div className="w-full h-full flex flex-col items-center justify-center text-gray-400 dark:text-slate-600">
                  <ImageIcon className="w-12 h-12 mb-2 opacity-50" />
                  <span className="text-sm">{t('noImageUploaded')}</span>
                </div>
              )}
            </div>

            {/* RIGHT: Details */}
            <div className="w-full md:w-1/2 p-6 flex flex-col">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-1">{selectedDonation.name}</h2>
                  <p className="text-emerald-400 font-medium">{selectedDonation.quantity} {selectedDonation.unit} • {selectedDonation.foodType}</p>
                </div>
                <button onClick={() => { setSelectedDonation(null); setCurrentImageIndex(0); }} className="p-1 hover:bg-gray-100 dark:hover:bg-gray-100 dark:bg-slate-800 rounded-full text-gray-500 dark:text-slate-400 transition-colors">
                  <X className="w-5 h-5" />
                </button>
              </div>

              <div className="space-y-3">
                <div className="p-3 bg-gray-100/80 dark:bg-slate-800/50 rounded-lg border border-gray-200 dark:border-slate-800">
                  <p className="text-xs text-gray-500 dark:text-slate-400 uppercase tracking-wider mb-1">{t('donor')}</p>
                  <div className="flex justify-between items-center">
                    <span className="text-gray-900 dark:text-white font-medium">{selectedDonation.donorName}</span>
                    <div className="flex items-center gap-1.5 bg-emerald-500/10 px-2 py-0.5 rounded text-emerald-400 text-xs">
                      <Shield className="w-3 h-3" />
                      <span>Trust: {selectedDonation.donorTrustScore?.toFixed(1) || 'N/A'}</span>
                    </div>
                  </div>
                </div>

                {/* Description */}
                {selectedDonation.description && (
                  <div>
                    <p className="text-xs text-gray-500 dark:text-slate-400 mb-1">{t('description')}</p>
                    <p className="text-sm text-gray-700 dark:text-slate-300 leading-relaxed">{selectedDonation.description}</p>
                  </div>
                )}

                {/* Hygiene */}
                <div>
                  <p className="text-xs text-gray-500 dark:text-slate-400 mb-2">{t('safetyCheck')}</p>
                  <div className="flex gap-2">
                    {selectedDonation.hygiene?.keptCovered ? (
                      <span className="flex items-center gap-1 text-xs bg-emerald-500/10 text-emerald-400 px-2 py-1 rounded border border-emerald-500/20">
                        <CheckCircle2 className="w-3 h-3" /> {t('keptCovered')}
                      </span>
                    ) : (
                      <span className="flex items-center gap-1 text-xs bg-red-500/10 text-red-400 px-2 py-1 rounded border border-red-500/20">
                        <X className="w-3 h-3" /> {t('notCovered')}
                      </span>
                    )}
                    {selectedDonation.hygiene?.containerClean ? (
                      <span className="flex items-center gap-1 text-xs bg-emerald-500/10 text-emerald-400 px-2 py-1 rounded border border-emerald-500/20">
                        <CheckCircle2 className="w-3 h-3" /> {t('cleanContainer')}
                      </span>
                    ) : (
                      <span className="flex items-center gap-1 text-xs bg-red-500/10 text-red-400 px-2 py-1 rounded border border-red-500/20">
                        <X className="w-3 h-3" /> {t('dirtyContainer')}
                      </span>
                    )}
                  </div>
                </div>

                {/* Time */}
                <div className="flex items-center gap-2 text-sm text-gray-500 dark:text-slate-400">
                  <Clock className="w-4 h-4" />
                  <span>{t('prepared', { time: new Date(selectedDonation.preparationTime).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'}) })}</span>
                </div>
              </div>

              {/* Action Button */}
              <div className="mt-6 pt-4 border-t border-gray-200 dark:border-slate-800">
                <div className="text-center p-3 bg-emerald-500/10 text-emerald-400 rounded-lg font-medium border border-emerald-500/20">
                  Your Donation - Status: {selectedDonation.status}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

import { useEffect, useMemo, useState, type FormEvent } from 'react'
import { Star, MessageCircle, Loader2, AlertCircle, TrendingUp } from 'lucide-react'
import { getDonations, createFeedback, getFeedbackForDonation, getDonorAverageRating, type Donation, type FeedbackItem } from '../../services/api'
import { useTranslation } from 'react-i18next'

export default function FeedbackRatings() {
  const [deliveredDonations, setDeliveredDonations] = useState<Donation[]>([])
  const [selectedDonationId, setSelectedDonationId] = useState('')
  const [rating, setRating] = useState(5)
  const [comment, setComment] = useState('')
  const [reviews, setReviews] = useState<FeedbackItem[]>([])
  const [loading, setLoading] = useState(true)
  const [submitting, setSubmitting] = useState(false)
  const [error, setError] = useState<string | null>(null)
  const [successMsg, setSuccessMsg] = useState<string | null>(null)
  const [donorRating, setDonorRating] = useState<{ averageScore: number; totalReviews: number } | null>(null)
  const { t } = useTranslation()

  const user = JSON.parse(localStorage.getItem('user') || '{}') as { id?: string; role?: string }
  const isNGO = user.role === 'NGO'
  const isDonor = user.role === 'DONOR'

  useEffect(() => {
    loadData()
  }, [])

  const loadData = async () => {
    setLoading(true)
    setError(null)
    try {
      const allDonations = await getDonations()
      // Show delivered donations that the current NGO claimed
      const delivered = allDonations.filter((d: Donation) => d.status === 'DELIVERED')
      setDeliveredDonations(delivered)

      // Load feedback for all delivered donations
      const allFeedback: FeedbackItem[] = []
      for (const donation of delivered) {
        try {
          const feedback = await getFeedbackForDonation(donation.id)
          allFeedback.push(...feedback)
        } catch {
          // donation may not have feedback yet
        }
      }
      setReviews(allFeedback)

      // For donors, fetch their average rating
      if (isDonor && user.id) {
        try {
          const avg = await getDonorAverageRating(user.id)
          setDonorRating(avg)
        } catch {
          // No ratings yet
        }
      }
    } catch (err: unknown) {
      const error = err as { response?: { data?: { message?: string } }, message?: string };
      setError(error?.response?.data?.message || error?.message || 'Failed to load data')
    } finally {
      setLoading(false)
    }
  }

  // Donations that haven't been reviewed yet by this user
  const unreviewedDonations = useMemo(() => {
    const reviewedIds = new Set(reviews.map(r => r.donationId))
    return deliveredDonations.filter(d => !reviewedIds.has(d.id))
  }, [deliveredDonations, reviews])

  const avgRating = useMemo(() => {
    if (!reviews.length) return 0
    const total = reviews.reduce((sum, r) => sum + r.rating, 0)
    return total / reviews.length
  }, [reviews])

  const submitReview = async (event: FormEvent) => {
    event.preventDefault()
    if (!selectedDonationId) return
    setSubmitting(true)
    setError(null)
    setSuccessMsg(null)
    try {
      const newFeedback = await createFeedback({
        donationId: selectedDonationId,
        rating,
        comment: comment.trim() || undefined,
      })
      setReviews(prev => [newFeedback, ...prev])
      setComment('')
      setRating(5)
      setSelectedDonationId('')
      setSuccessMsg(t('feedbackSubmitted'))
      setTimeout(() => setSuccessMsg(null), 3000)
    } catch (err: unknown) {
      const error = err as { response?: { data?: { message?: string } }, message?: string };
      setError(error?.response?.data?.message || error?.message || 'Failed to submit feedback')
    } finally {
      setSubmitting(false)
    }
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[400px]">
        <Loader2 className="w-8 h-8 animate-spin text-emerald-500" />
      </div>
    )
  }

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-semibold text-white">{t('ngoFeedbackRatings')}</h1>
        <p className="text-slate-400 mt-1">{t('feedbackDesc')}</p>
      </div>

      {error && (
        <div className="bg-red-500/10 border border-red-500/30 rounded-xl p-4 flex items-center gap-3">
          <AlertCircle className="w-5 h-5 text-red-400 flex-shrink-0" />
          <p className="text-red-400 text-sm">{error}</p>
        </div>
      )}

      {successMsg && (
        <div className="bg-emerald-500/10 border border-emerald-500/30 rounded-xl p-4">
          <p className="text-emerald-400 text-sm">{successMsg}</p>
        </div>
      )}

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-4">
        {/* Donor Rating Summary */}
        {isDonor && donorRating && (
          <div className="xl:col-span-3 card p-5">
            <div className="flex items-center gap-4">
              <div className="w-14 h-14 rounded-xl bg-amber-500/10 flex items-center justify-center">
                <TrendingUp className="w-7 h-7 text-amber-400" />
              </div>
              <div>
                <p className="text-sm text-slate-400">{t('yourDonorRating')}</p>
                <div className="flex items-center gap-3 mt-1">
                  <span className="text-3xl font-bold text-white">{donorRating.averageScore.toFixed(1)}</span>
                  <span className="text-amber-400 text-lg">{'★'.repeat(Math.round(donorRating.averageScore))}{'☆'.repeat(5 - Math.round(donorRating.averageScore))}</span>
                </div>
                <p className="text-xs text-slate-500 mt-1">{t('basedOnReviews', { count: donorRating.totalReviews })}</p>
              </div>
            </div>
          </div>
        )}
        {isNGO && (
          <div className="card p-5 xl:col-span-1">
            <h2 className="text-white font-semibold mb-4 flex items-center gap-2">
              <MessageCircle className="w-5 h-5 text-emerald-400" />
              {t('leaveReview')}
            </h2>
            {unreviewedDonations.length === 0 ? (
              <p className="text-slate-400 text-sm">{t('noDeliveredAwaiting')}</p>
            ) : (
              <form onSubmit={submitReview} className="space-y-3">
                <select
                  className="select-field"
                  value={selectedDonationId}
                  onChange={(e) => setSelectedDonationId(e.target.value)}
                >
                  <option value="">{t('selectDeliveredDonation')}</option>
                  {unreviewedDonations.map(d => (
                    <option key={d.id} value={d.id}>
                      {d.name} — {d.donorName || t('unknownDonor')}
                    </option>
                  ))}
                </select>
                <select className="select-field" value={rating} onChange={(e) => setRating(Number(e.target.value))}>
                  <option value={5}>5 {t('stars')}</option>
                  <option value={4}>4 {t('stars')}</option>
                  <option value={3}>3 {t('stars')}</option>
                  <option value={2}>2 {t('stars')}</option>
                  <option value={1}>1 {t('starSingular')}</option>
                </select>
                <textarea
                  className="input-field min-h-[100px]"
                  placeholder={t('shareFeedbackPlaceholder')}
                  value={comment}
                  onChange={(e) => setComment(e.target.value)}
                />
                <button
                  type="submit"
                  className="btn-primary w-full"
                  disabled={!selectedDonationId || submitting}
                >
                  {submitting ? t('submitting') : t('submitFeedback')}
                </button>
              </form>
            )}
          </div>
        )}

        {/* Rating Summary & Reviews */}
        <div className={`card p-5 space-y-4 ${isNGO ? 'xl:col-span-2' : 'xl:col-span-3'}`}>
          <div className="flex items-center justify-between">
            <h2 className="text-white font-semibold">{t('ratingSummary')}</h2>
            <span className="badge badge-success flex items-center gap-1">
              <Star className="w-3 h-3" />
              {avgRating.toFixed(1)} / 5
            </span>
          </div>

          {reviews.length === 0 ? (
            <p className="text-slate-400 text-sm py-8 text-center">{t('noFeedbackYet')}</p>
          ) : (
            <div className="space-y-3">
              {reviews.map((review) => (
                <div key={review.id} className="bg-slate-900 border border-slate-800 rounded-xl p-4">
                  <div className="flex items-center justify-between gap-2">
                    <p className="text-white font-medium">{review.ngo?.name || 'NGO'}</p>
                    <div className="text-amber-400 text-sm">{'★'.repeat(review.rating)}{'☆'.repeat(5 - review.rating)}</div>
                  </div>
                  {review.comment && <p className="text-sm text-slate-300 mt-2">{review.comment}</p>}
                  <p className="text-xs text-slate-500 mt-2">{new Date(review.createdAt).toLocaleDateString()}</p>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

import { useEffect, useState, useRef, useCallback } from 'react'
import { Link } from 'react-router-dom'
import { useTranslation } from 'react-i18next'
import { getDonations, claimDonation, type Donation } from '../../services/api'
import { socketService } from '../../services/socket'
import { Map, TrendingUp, Clock, X, Image as ImageIcon, Shield, CheckCircle2, MapPin, ChevronLeft, ChevronRight, Navigation2, Radio } from 'lucide-react'
import { toast } from 'sonner'
import { MapContainer, TileLayer, Marker, Polyline, useMap } from 'react-leaflet'
import L from 'leaflet'
import 'leaflet/dist/leaflet.css'

// Fix for default marker icons
// eslint-disable-next-line @typescript-eslint/no-explicit-any
delete (L.Icon.Default.prototype as any)._getIconUrl
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon-2x.png',
  iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon.png',
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png',
})

const volunteerIcon = new L.DivIcon({
  className: 'volunteer-live-marker',
  html: `<div style="width:16px;height:16px;background:#3b82f6;border-radius:50%;border:3px solid white;box-shadow:0 0 0 4px rgba(59,130,246,0.35),0 2px 6px rgba(0,0,0,0.3);"></div>`,
  iconSize: [16, 16],
  iconAnchor: [8, 8],
})

const pickupIcon = new L.DivIcon({
  className: 'pickup-marker',
  html: `<div style="width:14px;height:14px;background:#10b981;border-radius:50%;border:2px solid white;box-shadow:0 2px 6px rgba(0,0,0,0.3);"></div>`,
  iconSize: [14, 14],
  iconAnchor: [7, 7],
})

function MapFollower({ position }: { position: [number, number] }) {
  const map = useMap()
  useEffect(() => {
    map.flyTo(position, map.getZoom(), { duration: 0.5 })
  }, [position, map])
  return null
}

export default function NGODashboard() {
  const { t } = useTranslation()
  const [donations, setDonations] = useState<Donation[]>([])
  const [loading, setLoading] = useState(false)
  const [selectedDonation, setSelectedDonation] = useState<Donation | null>(null)
  const [claiming, setClaiming] = useState<string | null>(null)
  const [currentImageIndex, setCurrentImageIndex] = useState(0)
  const [trackingDonation, setTrackingDonation] = useState<Donation | null>(null)
  const [volunteerPos, setVolunteerPos] = useState<{ lat: number; lng: number } | null>(null)
  const [lastUpdate, setLastUpdate] = useState<string | null>(null)
  const [routeHistory, setRouteHistory] = useState<[number, number][]>([])
  const trackingUnsubRef = useRef<(() => void) | null>(null)

  const user = JSON.parse(localStorage.getItem('user') || '{}')

  // ── Live Tracking ──────────────────────────────────
  const openTracking = useCallback((donation: Donation) => {
    // Clean up previous subscription
    if (trackingUnsubRef.current) trackingUnsubRef.current()
    setVolunteerPos(null)
    setLastUpdate(null)
    setRouteHistory([])
    setTrackingDonation(donation)

    // Subscribe to real-time volunteer location for this donation
    trackingUnsubRef.current = socketService.onVolunteerLocation(donation.id, (loc) => {
      setVolunteerPos({ lat: loc.lat, lng: loc.lng })
      setLastUpdate(loc.timestamp)
      setRouteHistory(prev => [...prev, [loc.lat, loc.lng]])
    })
  }, [])

  const closeTracking = useCallback(() => {
    if (trackingUnsubRef.current) {
      trackingUnsubRef.current()
      trackingUnsubRef.current = null
    }
    setTrackingDonation(null)
    setVolunteerPos(null)
    setLastUpdate(null)
    setRouteHistory([])
  }, [])

  // Cleanup tracking subscription on unmount
  useEffect(() => () => { if (trackingUnsubRef.current) trackingUnsubRef.current() }, [])

  const load = async () => {
    setLoading(true)
    try {
      const data = await getDonations({
        role: 'ngo',
        userId: user.id
      })
      setDonations(data)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    load()

    // Listen for new donations (socket is already connected by DashboardLayout)
    const unsubscribeCreated = socketService.onDonationCreated((data) => {
      toast.success(`🍕 ${t('newFoodAlert')}: ${data.foodType}!`, {
        description: `${data.name} - ${data.location.address}`,
        duration: 5000,
      })
      // Re-fetch donations to show the new item
      load()
    })

    // Listen for claimed donations
    const unsubscribeClaimed = socketService.onDonationClaimed((data) => {
      toast.info(`🔔 ${t('foodClaimedAlert')}`, {
        description: `${data.donationId} has been claimed`,
        duration: 3000,
      })
      // Remove the claimed donation from state
      setDonations((prevDonations) =>
        prevDonations.filter((donation) => donation.id !== data.donationId)
      )
      // Close modal if it was for this donation
      if (selectedDonation?.id === data.donationId) {
        setSelectedDonation(null)
        setCurrentImageIndex(0)
      }
    })

    return () => {
      unsubscribeCreated()
      unsubscribeClaimed()
    }
  }, [])

  const availableCount = donations.filter((d) => d.status === 'AVAILABLE').length
  const claimedCount = donations.filter((d) => d.status === 'CLAIMED' || d.status === 'PICKED_UP').length
  const deliveredCount = donations.filter((d) => d.status === 'DELIVERED').length

  const getTimeRemaining = (expiryTime: Date) => {
    const now = new Date()
    const remaining = new Date(expiryTime).getTime() - now.getTime()

    if (remaining <= 0) return { expired: true, urgent: false, hours: 0, minutes: 0 }

    const hours = Math.floor(remaining / (1000 * 60 * 60))
    const minutes = Math.floor((remaining % (1000 * 60 * 60)) / (1000 * 60))
    const urgent = hours < 3

    return { expired: false, urgent, hours, minutes }
  }

  const handleClaim = async (donationId: string) => {
    setClaiming(donationId)
    try {
      await claimDonation(donationId)
      await load()
      setSelectedDonation(null)
    } catch (err: unknown) {
      const error = err as { response?: { data?: { message?: string } }, message?: string };
      const msg =
        error?.response?.data?.message ||
        error?.message ||
        'Failed to claim donation'
      toast.error('Unable to claim', { description: msg })
    } finally {
      setClaiming(null)
    }
  }

  const getStatusStyle = (status: string) => {
    const styles: Record<string, string> = {
      AVAILABLE: 'bg-emerald-500/10 text-emerald-400',
      CLAIMED: 'bg-amber-500/10 text-amber-400',
      PICKED_UP: 'bg-blue-500/10 text-blue-400',
      DELIVERED: 'bg-slate-500/10 text-gray-500 dark:text-slate-400',
      EXPIRED: 'bg-red-500/10 text-red-400',
    }
    return styles[status] || styles.AVAILABLE
  }

  const getGreeting = () => {
    const hour = new Date().getHours()
    if (hour < 12) return t('goodMorning')
    if (hour < 18) return t('goodAfternoon')
    return t('goodEvening')
  }

  return (
    <div>
      {/* Header */}
      <div className="mb-8">
        <h1 className="text-2xl font-semibold text-gray-900 dark:text-white">
          {getGreeting()}, {user.organizationName || user.name?.split(' ')[0] || 'there'}!
        </h1>
        <p className="text-gray-500 dark:text-slate-500 mt-1">
          {t('findClaimDonations')}
        </p>
      </div>

      {/* NGO Capacity Info */}
      {user.dailyIntakeCapacity && (
        <div className="mb-6 p-4 bg-blue-500/10 border border-blue-500/20 rounded-xl">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-blue-400 mb-1">{t('dailyIntakeCapacity')}</p>
              <p className="text-xs text-gray-500 dark:text-slate-400">
                Current load: <span className="text-blue-400 font-semibold">{user.currentIntakeLoad}</span> / <span className="text-blue-400 font-semibold">{user.dailyIntakeCapacity}</span> {user.capacityUnit || 'kg'}
              </p>
            </div>
            <div className="w-24 h-2 bg-gray-100 dark:bg-slate-800 rounded-full overflow-hidden">
              <div
                className="h-full bg-blue-500 transition-all"
                style={{ width: `${Math.min((user.currentIntakeLoad / user.dailyIntakeCapacity) * 100, 100)}%` }}
              />
            </div>
          </div>
        </div>
      )}

      {/* Status Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
        <div className="rounded-xl border border-emerald-500/20 bg-emerald-500/10 p-5">
          <div className="flex items-center justify-between mb-3">
            <span className="text-xl text-emerald-400">●</span>
            <span className="text-xs font-medium px-2 py-0.5 rounded bg-emerald-500/10 text-emerald-400 uppercase">
              {t('available')}
            </span>
          </div>
          <p className="text-sm text-gray-500 dark:text-slate-400 mb-1">{t('readyToClaim')}</p>
          <p className="text-3xl font-semibold text-emerald-400">{availableCount}</p>
        </div>

        <div className="rounded-xl border border-amber-500/20 bg-amber-500/10 p-5">
          <div className="flex items-center justify-between mb-3">
            <span className="text-xl text-amber-400">◷</span>
            <span className="text-xs font-medium px-2 py-0.5 rounded bg-amber-500/10 text-amber-400 uppercase">
              {t('inProgress')}
            </span>
          </div>
          <p className="text-sm text-gray-500 dark:text-slate-400 mb-1">{t('claimedPending')}</p>
          <p className="text-3xl font-semibold text-amber-400">{claimedCount}</p>
        </div>

        <div className="rounded-xl border border-gray-300 dark:border-slate-700 bg-gray-100/50 dark:bg-slate-800/30 p-5">
          <div className="flex items-center justify-between mb-3">
            <span className="text-xl text-gray-500 dark:text-slate-400">✓</span>
            <span className="text-xs font-medium px-2 py-0.5 rounded bg-slate-500/10 text-gray-500 dark:text-slate-400 uppercase">
              {t('complete')}
            </span>
          </div>
          <p className="text-sm text-gray-500 dark:text-slate-400 mb-1">{t('delivered')}</p>
          <p className="text-3xl font-semibold text-gray-500 dark:text-slate-400">{deliveredCount}</p>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-8">
        <Link
          to="/dashboard/map"
          className="group p-6 rounded-xl bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 hover:border-gray-300 dark:hover:border-gray-300 dark:border-slate-700 transition-all"
        >
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 rounded-xl bg-gray-100 dark:bg-slate-800 flex items-center justify-center text-gray-500 dark:text-slate-400 group-hover:text-gray-900 dark:group-hover:text-white transition-colors">
              <Map className="w-6 h-6" />
            </div>
            <div>
              <h3 className="font-semibold text-gray-900 dark:text-white mb-1">{t('discoveryMap')}</h3>
              <p className="text-sm text-gray-500 dark:text-slate-400">{t('findClaimDonations')}</p>
            </div>
          </div>
        </Link>

        <Link
          to="/dashboard/impact"
          className="group p-6 rounded-xl bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 hover:border-gray-300 dark:hover:border-gray-300 dark:border-slate-700 transition-all"
        >
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 rounded-xl bg-gray-100 dark:bg-slate-800 flex items-center justify-center text-gray-500 dark:text-slate-400 group-hover:text-gray-900 dark:group-hover:text-white transition-colors">
              <TrendingUp className="w-6 h-6" />
            </div>
            <div>
              <h3 className="font-semibold text-gray-900 dark:text-white mb-1">{t('yourImpact')}</h3>
              <p className="text-sm text-gray-500 dark:text-slate-400">{t('seeDifference')}</p>
            </div>
          </div>
        </Link>
      </div>

      {/* Available Donations */}
      <div className="bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-xl overflow-hidden mb-8">
        <div className="p-5 border-b border-gray-200 dark:border-slate-800 flex items-center justify-between">
          <h2 className="font-medium text-gray-900 dark:text-white">
            {t('availableDonationsToClaim')}
          </h2>
          <Link to="/dashboard/history" className="text-sm text-emerald-400 hover:text-emerald-300">
            {t('viewAll')}
          </Link>
        </div>

        {loading && (
          <div className="p-8 text-center text-gray-500 dark:text-slate-500">{t('loading')}</div>
        )}

        {!loading && donations.filter(d => d.status === 'AVAILABLE').length === 0 && (
          <div className="p-8 text-center">
            <p className="text-gray-500 dark:text-slate-500 mb-4">
              {t('noAvailableDonations')}
            </p>
          </div>
        )}

        <div className="divide-y divide-gray-200 dark:divide-slate-800">
          {donations.filter(d => d.status === 'AVAILABLE').slice(0, 5).map((donation) => {
            const timeLeft = getTimeRemaining(donation.expiryTime)
            return (
              <div key={donation.id} className="p-4 hover:bg-gray-100/50 dark:bg-slate-800/30 transition-colors">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-4 flex-1">
                    <div className={`w-12 h-12 rounded-lg flex items-center justify-center text-2xl ${timeLeft.urgent ? 'bg-red-500/10' : 'bg-emerald-500/10'
                      }`}>
                      {donation.foodType === 'cooked' && '🍛'}
                      {donation.foodType === 'raw' && '🥬'}
                      {donation.foodType === 'packaged' && '📦'}
                      {donation.foodType === 'fruits' && '🍎'}
                      {donation.foodType === 'bakery' && '🥖'}
                      {donation.foodType === 'dairy' && '🥛'}
                    </div>
                    <div className="flex-1">
                      <div className="flex items-center gap-2 mb-1">
                        <p className="font-medium text-gray-900 dark:text-white">{donation.name}</p>
                        {timeLeft.urgent && (
                          <span className="text-xs px-1.5 py-0.5 bg-red-500/10 text-red-400 rounded flex items-center gap-1">
                            <Clock className="w-3 h-3" />
                            {timeLeft.hours}h {timeLeft.minutes}m
                          </span>
                        )}
                      </div>
                      <p className="text-sm text-gray-500 dark:text-slate-500">
                        {donation.quantity} {donation.unit} • {donation.donorName}
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <button
                      onClick={() => setSelectedDonation(donation)}
                      className="px-3 py-1 rounded-md text-xs font-medium bg-gray-100 dark:bg-slate-800 text-gray-700 dark:text-slate-300 hover:bg-gray-200 dark:hover:bg-gray-200 dark:bg-slate-700 transition-colors border border-gray-300 dark:border-slate-700"
                    >
                      {t('viewDetails')}
                    </button>
                    <span className={`px-3 py-1 rounded-md text-xs font-medium whitespace-nowrap ${getStatusStyle(donation.status)}`}>
                      {t('available')}
                    </span>
                  </div>
                </div>
              </div>
            )
          })}
        </div>
      </div>

      {/* Claimed Donations */}
      <div className="bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-xl overflow-hidden">
        <div className="p-5 border-b border-gray-200 dark:border-slate-800">
          <h2 className="font-medium text-gray-900 dark:text-white">{t('yourClaimedDonations')}</h2>
        </div>

        {!loading && donations.filter(d => d.status === 'CLAIMED' || d.status === 'PICKED_UP').length === 0 && (
          <div className="p-8 text-center">
            <p className="text-gray-500 dark:text-slate-500">{t('noClaimedDonations')}</p>
          </div>
        )}

        <div className="divide-y divide-gray-200 dark:divide-slate-800">
          {donations.filter(d => d.status === 'CLAIMED' || d.status === 'PICKED_UP').map((donation) => {
            return (
              <div key={donation.id} className="p-4 hover:bg-gray-100/50 dark:bg-slate-800/30 transition-colors">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-4 flex-1">
                    <div className="w-12 h-12 rounded-lg flex items-center justify-center text-2xl bg-amber-500/10">
                      {donation.foodType === 'cooked' && '🍛'}
                      {donation.foodType === 'raw' && '🥬'}
                      {donation.foodType === 'packaged' && '📦'}
                      {donation.foodType === 'fruits' && '🍎'}
                      {donation.foodType === 'bakery' && '🥖'}
                      {donation.foodType === 'dairy' && '🥛'}
                    </div>
                    <div className="flex-1">
                      <p className="font-medium text-gray-900 dark:text-white">{donation.name}</p>
                      <p className="text-sm text-gray-500 dark:text-slate-500">
                        {donation.quantity} {donation.unit} • {donation.donorName}
                      </p>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <button
                      onClick={() => openTracking(donation)}
                      className="px-3 py-1 rounded-md text-xs font-medium bg-blue-500/10 text-blue-400 hover:bg-blue-500/20 transition-colors border border-blue-500/20 flex items-center gap-1"
                    >
                      <Navigation2 className="w-3 h-3" />
                      Track Volunteer
                    </button>
                    <button
                      onClick={() => setSelectedDonation(donation)}
                      className="px-3 py-1 rounded-md text-xs font-medium bg-gray-100 dark:bg-slate-800 text-gray-700 dark:text-slate-300 hover:bg-gray-200 dark:hover:bg-gray-200 dark:bg-slate-700 transition-colors border border-gray-300 dark:border-slate-700"
                    >
                      {t('viewDetails')}
                    </button>
                    <span className={`px-3 py-1 rounded-md text-xs font-medium whitespace-nowrap ${getStatusStyle(donation.status)}`}>
                      {donation.status === 'PICKED_UP' ? t('pickedUp') : t('claimed')}
                    </span>
                  </div>
                </div>
              </div>
            )
          })}
        </div>
      </div>

      {/* Detail Modal */}
      {selectedDonation && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center p-4 bg-black/30 dark:bg-slate-950/80 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-xl w-full max-w-2xl max-h-[90vh] overflow-y-auto shadow-2xl flex flex-col md:flex-row">

            {/* LEFT: Image Section */}
            <div className="w-full md:w-1/2 bg-gray-50 dark:bg-slate-950 h-64 md:h-auto relative group">
              {selectedDonation.imageUrls && selectedDonation.imageUrls.length > 0 ? (
                <>
                  <img
                    src={selectedDonation.imageUrls[currentImageIndex]}
                    alt={selectedDonation.name}
                    className="w-full h-full object-cover"
                  />
                  {/* Image Counter */}
                  <div className="absolute bottom-4 right-4 bg-black/60 text-gray-900 dark:text-white text-xs px-3 py-1 rounded-full">
                    {currentImageIndex + 1} / {selectedDonation.imageUrls.length}
                  </div>
                  {/* Navigation Buttons */}
                  {selectedDonation.imageUrls.length > 1 && (
                    <>
                      <button
                        onClick={() => setCurrentImageIndex((prev) => (prev - 1 + selectedDonation.imageUrls.length) % selectedDonation.imageUrls.length)}
                        className="absolute left-4 top-1/2 transform -translate-y-1/2 bg-black/50 hover:bg-black/70 text-gray-900 dark:text-white p-2 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"
                      >
                        <ChevronLeft className="w-5 h-5" />
                      </button>
                      <button
                        onClick={() => setCurrentImageIndex((prev) => (prev + 1) % selectedDonation.imageUrls.length)}
                        className="absolute right-4 top-1/2 transform -translate-y-1/2 bg-black/50 hover:bg-black/70 text-gray-900 dark:text-white p-2 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"
                      >
                        <ChevronRight className="w-5 h-5" />
                      </button>
                    </>
                  )}
                </>
              ) : (
                <div className="w-full h-full flex flex-col items-center justify-center text-gray-400 dark:text-slate-600">
                  <ImageIcon className="w-12 h-12 mb-2 opacity-50" />
                  <span className="text-sm">{t('noImageUploaded')}</span>
                </div>
              )}
            </div>

            {/* RIGHT: Details */}
            <div className="w-full md:w-1/2 p-6 flex flex-col">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <h2 className="text-xl font-bold text-gray-900 dark:text-white mb-1">{selectedDonation.name}</h2>
                  <p className="text-emerald-400 font-medium">{selectedDonation.quantity} {selectedDonation.unit} • {selectedDonation.foodType}</p>
                </div>
                <button onClick={() => { setSelectedDonation(null); setCurrentImageIndex(0); }} className="p-1 hover:bg-gray-100 dark:hover:bg-gray-100 dark:bg-slate-800 rounded-full text-gray-500 dark:text-slate-400 transition-colors">
                  <X className="w-5 h-5" />
                </button>
              </div>

              <div className="space-y-3 flex-1 overflow-y-auto">
                <div className="p-3 bg-gray-100/80 dark:bg-slate-800/50 rounded-lg border border-gray-200 dark:border-slate-800">
                  <p className="text-xs text-gray-500 dark:text-slate-400 uppercase tracking-wider mb-1">{t('donor')}</p>
                  <div className="flex justify-between items-center">
                    <span className="text-gray-900 dark:text-white font-medium">{selectedDonation.donorName}</span>
                    <div className="flex items-center gap-1.5 bg-emerald-500/10 px-2 py-0.5 rounded text-emerald-400 text-xs">
                      <Shield className="w-3 h-3" />
                      <span>Trust: {selectedDonation.donorTrustScore?.toFixed(1) || 'N/A'}</span>
                    </div>
                  </div>
                </div>

                {/* Description */}
                {selectedDonation.description && (
                  <div>
                    <p className="text-xs text-gray-500 dark:text-slate-400 mb-1">{t('description')}</p>
                    <p className="text-sm text-gray-700 dark:text-slate-300 leading-relaxed">{selectedDonation.description}</p>
                  </div>
                )}

                {/* Hygiene */}
                <div>
                  <p className="text-xs text-gray-500 dark:text-slate-400 mb-2">{t('safetyCheck')}</p>
                  <div className="flex gap-2 flex-wrap">
                    {selectedDonation.hygiene?.keptCovered ? (
                      <span className="flex items-center gap-1 text-xs bg-emerald-500/10 text-emerald-400 px-2 py-1 rounded border border-emerald-500/20">
                        <CheckCircle2 className="w-3 h-3" /> {t('keptCovered')}
                      </span>
                    ) : (
                      <span className="flex items-center gap-1 text-xs bg-red-500/10 text-red-400 px-2 py-1 rounded border border-red-500/20">
                        <X className="w-3 h-3" /> {t('notCovered')}
                      </span>
                    )}
                    {selectedDonation.hygiene?.containerClean ? (
                      <span className="flex items-center gap-1 text-xs bg-emerald-500/10 text-emerald-400 px-2 py-1 rounded border border-emerald-500/20">
                        <CheckCircle2 className="w-3 h-3" /> {t('cleanContainer')}
                      </span>
                    ) : (
                      <span className="flex items-center gap-1 text-xs bg-red-500/10 text-red-400 px-2 py-1 rounded border border-red-500/20">
                        <X className="w-3 h-3" /> {t('dirtyContainer')}
                      </span>
                    )}
                  </div>
                </div>

                {/* Location */}
                <div>
                  <p className="text-xs text-gray-500 dark:text-slate-400 mb-1">{t('pickupLocation')}</p>
                  <p className="text-sm text-gray-700 dark:text-slate-300">📍 {selectedDonation.location?.address || 'Location not specified'}</p>
                </div>

                {/* Time */}
                <div className="flex items-center gap-2 text-sm text-gray-500 dark:text-slate-400">
                  <Clock className="w-4 h-4" />
                  <span>{t('prepared', { time: new Date(selectedDonation.preparationTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) })}</span>
                </div>
              </div>

              {/* Action Button */}
              <div className="mt-6 pt-4 border-t border-gray-200 dark:border-slate-800">
                {!user.isVerified ? (
                  <div className="text-center p-3 bg-amber-500/10 text-amber-400 rounded-lg text-sm font-medium border border-amber-500/20">
                    ⏳ {t('verificationPending')} — {t('verificationPendingDesc') || 'You cannot claim donations until your account is verified.'}
                  </div>
                ) : selectedDonation.status === 'AVAILABLE' ? (
                  <button
                    onClick={() => handleClaim(selectedDonation.id)}
                    disabled={claiming === selectedDonation.id}
                    className="w-full py-3 bg-emerald-500 hover:bg-emerald-400 disabled:bg-gray-200 dark:bg-slate-700 text-white rounded-lg font-semibold transition-all shadow-lg shadow-emerald-500/20 flex items-center justify-center gap-2"
                  >
                    {claiming === selectedDonation.id ? (
                      <>{t('claiming')}</>
                    ) : (
                      <>
                        <MapPin className="w-4 h-4" />
                        {t('claimThisFood')}
                      </>
                    )}
                  </button>
                ) : (
                  <div className="space-y-2">
                    <div className="text-center p-3 bg-amber-500/10 text-amber-400 rounded-lg font-medium border border-amber-500/20">
                      {selectedDonation.status === 'CLAIMED' ? t('alreadyClaimed') : t('alreadyPickedUp')}
                    </div>
                    <button
                      onClick={() => { setSelectedDonation(null); setCurrentImageIndex(0); openTracking(selectedDonation); }}
                      className="w-full py-3 bg-blue-500 hover:bg-blue-400 text-white rounded-lg font-semibold transition-all shadow-lg shadow-blue-500/20 flex items-center justify-center gap-2"
                    >
                      <Navigation2 className="w-4 h-4" />
                      Track Volunteer Live
                    </button>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ── Live Volunteer Tracking Modal ────────────────── */}
      {trackingDonation && (
        <div className="fixed inset-0 z-[2100] flex items-center justify-center p-4 bg-black/30 dark:bg-slate-950/80 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-xl w-full max-w-xl shadow-2xl">
            {/* Header */}
            <div className="flex items-center justify-between p-5 border-b border-gray-200 dark:border-slate-800">
              <div>
                <h2 className="text-lg font-semibold text-gray-900 dark:text-white flex items-center gap-2">
                  <Navigation2 className="w-5 h-5 text-blue-400" />
                  Live Volunteer Tracking
                </h2>
                <p className="text-sm text-gray-500 dark:text-slate-400 mt-0.5">{trackingDonation.name}</p>
              </div>
              <div className="flex items-center gap-3">
                {volunteerPos && (
                  <span className="flex items-center gap-1.5 text-xs font-medium text-emerald-400">
                    <Radio className="w-3 h-3 animate-pulse" />
                    Live
                  </span>
                )}
                <button onClick={closeTracking} className="p-1.5 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-full text-gray-500 dark:text-slate-400 transition-colors">
                  <X className="w-5 h-5" />
                </button>
              </div>
            </div>

            {/* Map */}
            <div className="p-5">
              {volunteerPos ? (
                <>
                  <div className="rounded-xl overflow-hidden border border-gray-200 dark:border-slate-800" style={{ height: 350 }}>
                    <MapContainer
                      center={[volunteerPos.lat, volunteerPos.lng]}
                      zoom={15}
                      style={{ height: '100%', width: '100%' }}
                      zoomControl={true}
                    >
                      <TileLayer
                        attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
                        url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                      />
                      <MapFollower position={[volunteerPos.lat, volunteerPos.lng]} />

                      {/* Route trail */}
                      {routeHistory.length > 1 && (
                        <Polyline
                          positions={routeHistory}
                          pathOptions={{ color: '#3b82f6', weight: 4, opacity: 0.7, dashArray: '8 6' }}
                        />
                      )}

                      {/* Start marker */}
                      {routeHistory.length > 0 && (
                        <Marker position={routeHistory[0]} icon={pickupIcon} />
                      )}

                      {/* Current volunteer position */}
                      <Marker position={[volunteerPos.lat, volunteerPos.lng]} icon={volunteerIcon} />

                      {/* Pickup location marker */}
                      {trackingDonation?.location?.lat && trackingDonation?.location?.lng && (
                        <Marker
                          position={[trackingDonation.location.lat, trackingDonation.location.lng]}
                          icon={pickupIcon}
                        />
                      )}
                    </MapContainer>
                  </div>
                  <div className="flex items-center justify-between mt-3">
                    <p className="text-xs text-gray-500 dark:text-slate-500">
                      📍 {volunteerPos.lat.toFixed(5)}, {volunteerPos.lng.toFixed(5)}
                    </p>
                    <div className="flex items-center gap-3">
                      {routeHistory.length > 1 && (
                        <span className="text-xs text-blue-400">{routeHistory.length} points tracked</span>
                      )}
                      {lastUpdate && (
                        <p className="text-xs text-gray-400 dark:text-slate-600">
                          Updated {new Date(lastUpdate).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
                        </p>
                      )}
                    </div>
                  </div>
                </>
              ) : (
                <div className="rounded-xl border border-gray-200 dark:border-slate-800 bg-gray-50 dark:bg-slate-950 p-10 flex items-center justify-center" style={{ height: 350 }}>
                  <div className="text-center">
                    <Navigation2 className="w-10 h-10 text-gray-400 dark:text-slate-600 mx-auto mb-3 animate-pulse" />
                    <p className="text-gray-500 dark:text-slate-400 font-medium text-sm">Waiting for volunteer to share location…</p>
                    <p className="text-xs text-gray-400 dark:text-slate-600 mt-1">
                      The map will appear once the volunteer starts sharing their GPS.
                    </p>
                  </div>
                </div>
              )}
            </div>

            {/* Pickup info footer */}
            <div className="px-5 pb-5">
              <div className="p-3 bg-gray-100/80 dark:bg-slate-800/50 rounded-lg border border-gray-200 dark:border-slate-800">
                <p className="text-xs text-gray-500 dark:text-slate-400 uppercase tracking-wider mb-1">Pickup Location</p>
                <p className="text-sm text-gray-700 dark:text-slate-300">📍 {trackingDonation.location?.address || 'Unknown'}</p>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

import { useEffect, useState, type ReactElement } from 'react'
import { useTranslation } from 'react-i18next'
import { getNotifications, markNotificationRead, markAllNotificationsRead, type Notification } from '../../services/api'
import { socketService } from '../../services/socket'
import { Bell, CheckCircle, AlertTriangle, MapPin, Package } from 'lucide-react'

export default function Notifications() {
    const { t } = useTranslation()
    const [notifications, setNotifications] = useState<Notification[]>([])
    const [loading, setLoading] = useState(true)
    const [filter, setFilter] = useState<'all' | 'unread'>('all')

    const user = JSON.parse(localStorage.getItem('user') || '{}')

    useEffect(() => {
        loadNotifications()

        // Subscribe to real-time notifications
        const unsubNotif = socketService.onNotification((data) => {
            const mapped: Notification = {
                ...data,
                type: (['food_claimed', 'pickup_assigned', 'delivery_confirmed', 'near_expiry', 'new_food_nearby'].includes(data.type)
                    ? data.type
                    : 'new_food_nearby') as Notification['type'],
                createdAt: new Date(data.createdAt),
            };
            setNotifications(prev => [mapped, ...prev]);
        });

        return () => {
            unsubNotif();
        };
    }, [])

    const loadNotifications = async () => {
        setLoading(true)
        try {
            const data = await getNotifications(user.id)
            setNotifications(data.sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime()))
        } finally {
            setLoading(false)
        }
    }

    const handleMarkRead = async (id: string) => {
        await markNotificationRead(id)
        setNotifications(notifications.map(n =>
            n.id === id ? { ...n, read: true } : n
        ))
    }

    const handleMarkAllRead = async () => {
        await markAllNotificationsRead()
        setNotifications(notifications.map(n => ({ ...n, read: true })))
    }

    const filtered = filter === 'all'
        ? notifications
        : notifications.filter(n => !n.read)

    const unreadCount = notifications.filter(n => !n.read).length

    const getIcon = (type: Notification['type']) => {
        const icons: Record<Notification['type'], ReactElement> = {
            food_claimed: <Package className="w-5 h-5 text-emerald-400" />,
            pickup_assigned: <MapPin className="w-5 h-5 text-blue-400" />,
            delivery_confirmed: <CheckCircle className="w-5 h-5 text-green-400" />,
            near_expiry: <AlertTriangle className="w-5 h-5 text-amber-400" />,
            new_food_nearby: <Bell className="w-5 h-5 text-purple-400" />,
        }
        return icons[type] || <Bell className="w-5 h-5 text-gray-500 dark:text-slate-400" />
    }

    const formatTime = (date: Date) => {
        const now = new Date()
        const diff = now.getTime() - new Date(date).getTime()
        const minutes = Math.floor(diff / 60000)
        const hours = Math.floor(minutes / 60)
        const days = Math.floor(hours / 24)

        if (minutes < 1) return t('justNow')
        if (minutes < 60) return t('minutesAgo', { count: minutes })
        if (hours < 24) return t('hoursAgo', { count: hours })
        return t('daysAgo', { count: days })
    }

    return (
        <div>
            <div className="mb-8">
                <h1 className="text-2xl font-semibold text-gray-900 dark:text-white mb-1">{t('notifications')}</h1>
                <p className="text-gray-500 dark:text-slate-500">{t('stayUpdated')}</p>
            </div>

            {/* Header */}
            <div className="flex items-center justify-between mb-6">
                <div className="flex gap-2">
                    <button
                        onClick={() => setFilter('all')}
                        className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${filter === 'all'
                                ? 'bg-emerald-500 text-white'
                                : 'bg-white dark:bg-slate-900 text-gray-500 dark:text-slate-400 hover:text-gray-900 dark:hover:text-white'
                            }`}
                    >
                        {t('all')}
                    </button>
                    <button
                        onClick={() => setFilter('unread')}
                        className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${filter === 'unread'
                                ? 'bg-emerald-500 text-white'
                                : 'bg-white dark:bg-slate-900 text-gray-500 dark:text-slate-400 hover:text-gray-900 dark:hover:text-white'
                            }`}
                    >
                        {t('unread')} {unreadCount > 0 ? `(${unreadCount})` : ''}
                    </button>
                </div>

                {unreadCount > 0 && (
                    <button
                        onClick={handleMarkAllRead}
                        className="text-sm text-emerald-400 hover:text-emerald-300"
                    >
                        {t('markAllRead')}
                    </button>
                )}
            </div>

            {/* Notifications List */}
            <div className="space-y-2">
                {loading ? (
                    <div className="text-center py-12 text-gray-500 dark:text-slate-500">{t('loadingNotifications')}</div>
                ) : filtered.length === 0 ? (
                    <div className="text-center py-12">
                        <Bell className="w-12 h-12 text-gray-300 dark:text-slate-700 mx-auto mb-3" />
                        <p className="text-gray-500 dark:text-slate-500">
                            {filter === 'unread' ? t('noUnreadNotifications') : t('noNotificationsYet')}
                        </p>
                    </div>
                ) : (
                    filtered.map((notification) => (
                        <div
                            key={notification.id}
                            className={`p-4 rounded-lg border transition-all ${notification.read
                                    ? 'bg-white dark:bg-slate-900 border-gray-200 dark:border-slate-800'
                                    : 'bg-white/80 dark:bg-slate-900/50 border-emerald-500/30 shadow-lg shadow-emerald-500/5'
                                }`}
                        >
                            <div className="flex items-start gap-4">
                                <div className={`p-2 rounded-lg ${notification.read ? 'bg-gray-100 dark:bg-slate-800' : 'bg-gray-200 dark:bg-slate-800/80'
                                    }`}>
                                    {getIcon(notification.type)}
                                </div>

                                <div className="flex-1 min-w-0">
                                    <div className="flex items-start justify-between gap-4 mb-1">
                                        <h3 className={`font-medium ${notification.read ? 'text-gray-700 dark:text-slate-300' : 'text-gray-900 dark:text-white'
                                            }`}>
                                            {notification.title}
                                        </h3>
                                        <span className="text-xs text-gray-500 dark:text-slate-500 whitespace-nowrap">
                                            {formatTime(notification.createdAt)}
                                        </span>
                                    </div>
                                    <p className={`text-sm ${notification.read ? 'text-gray-500 dark:text-slate-500' : 'text-gray-500 dark:text-slate-400'
                                        }`}>
                                        {notification.message}
                                    </p>

                                    {!notification.read && (
                                        <button
                                            onClick={() => handleMarkRead(notification.id)}
                                            className="mt-3 text-xs text-emerald-400 hover:text-emerald-300"
                                        >
                                            {t('markAsRead')}
                                        </button>
                                    )}
                                </div>

                                {!notification.read && (
                                    <div className="w-2 h-2 rounded-full bg-emerald-500 flex-shrink-0 mt-2" />
                                )}
                            </div>
                        </div>
                    ))
                )}
            </div>
        </div>
    )
}

import { useCallback, useEffect, useMemo, useState, type FormEvent } from 'react'
import { MessageSquare, Send, ShieldCheck, Loader2, RefreshCw } from 'lucide-react'
import { adminAPI, supportAPI } from '../../services/api'
import { toast } from 'sonner'
import { useTranslation } from 'react-i18next'

type Ticket = {
  id: string
  subject: string
  description: string
  priority: 'LOW' | 'MEDIUM' | 'HIGH' | 'CRITICAL'
  status: 'OPEN' | 'IN_PROGRESS' | 'RESOLVED' | 'CLOSED'
  adminNote?: string
  createdAt: string
}

export default function SupportTickets() {
  const user = JSON.parse(localStorage.getItem('user') || '{}') as { role?: string }
  const isAdmin = (user.role || '').toUpperCase() === 'ADMIN'
  const { t } = useTranslation()

  const [tickets, setTickets] = useState<Ticket[]>([])
  const [loading, setLoading] = useState(true)
  const [subject, setSubject] = useState('')
  const [description, setDescription] = useState('')
  const [priority, setPriority] = useState<'LOW' | 'MEDIUM' | 'HIGH'>('MEDIUM')
  const [submitting, setSubmitting] = useState(false)

  const load = useCallback(async () => {
    setLoading(true)
    try {
      const res = isAdmin
        ? await adminAPI.getAllTickets()
        : await supportAPI.getMyTickets()
      const body = res.data
      setTickets(Array.isArray(body) ? body : Array.isArray(body?.data) ? body.data : [])
    } catch {
      toast.error(t('failedLoadTickets'))
      setTickets([])
    } finally {
      setLoading(false)
    }
  }, [isAdmin])

  useEffect(() => { load() }, [load])

  const grouped = useMemo(() => {
    const open = tickets.filter((t) => t.status === 'OPEN')
    const inProgress = tickets.filter((t) => t.status === 'IN_PROGRESS')
    const resolved = tickets.filter((t) => t.status === 'RESOLVED' || t.status === 'CLOSED')
    return { open, inProgress, resolved }
  }, [tickets])

  const submitTicket = async (event: FormEvent) => {
    event.preventDefault()
    if (!subject.trim() || !description.trim()) return
    setSubmitting(true)
    try {
      await supportAPI.createTicket({ subject: subject.trim(), description: description.trim(), priority })
      toast.success(t('ticketSubmitted'))
      setSubject('')
      setDescription('')
      setPriority('MEDIUM')
      load()
    } catch {
      toast.error(t('failedSubmitTicket'))
    } finally {
      setSubmitting(false)
    }
  }

  const advanceStatus = async (ticket: Ticket) => {
    const next = ticket.status === 'OPEN' ? 'IN_PROGRESS' : 'RESOLVED'
    try {
      await adminAPI.updateTicket(ticket.id, { status: next })
      toast.success(`Ticket moved to ${next.replace('_', ' ').toLowerCase()}`)
      load()
    } catch {
      toast.error(t('failedUpdateTicket'))
    }
  }

  const statusBadge = (status: string) => {
    if (status === 'RESOLVED' || status === 'CLOSED') return 'badge-success'
    if (status === 'IN_PROGRESS') return 'badge-warning'
    return 'badge-info'
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-semibold text-white">{t('supportTicketsTitle')}</h1>
          <p className="text-slate-400 mt-1">{t('supportDesc')}</p>
        </div>
        <button onClick={load} disabled={loading} className="p-2 text-slate-400 hover:text-emerald-400 rounded-lg">
          <RefreshCw className={`w-5 h-5 ${loading ? 'animate-spin' : ''}`} />
        </button>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-4">
        <form onSubmit={submitTicket} className="xl:col-span-1 card p-5 space-y-4">
          <h2 className="text-white font-semibold flex items-center gap-2">
            <MessageSquare className="w-5 h-5 text-amber-400" />
            {t('createTicket')}
          </h2>
          <input
            className="input-field"
            placeholder={t('issueSummaryPlaceholder')}
            value={subject}
            onChange={(e) => setSubject(e.target.value)}
            aria-label="Ticket subject"
          />
          <textarea
            className="input-field resize-none"
            placeholder={t('describeIssuePlaceholder')}
            rows={3}
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            aria-label="Ticket description"
          />
          <select className="select-field" value={priority} onChange={(e) => setPriority(e.target.value as 'LOW' | 'MEDIUM' | 'HIGH')}>
            <option value="LOW">{t('lowPriority')}</option>
            <option value="MEDIUM">{t('mediumPriority')}</option>
            <option value="HIGH">{t('highPriority')}</option>
          </select>
          <button type="submit" disabled={submitting} className="btn-primary w-full flex items-center justify-center gap-2 disabled:opacity-50">
            {submitting ? <Loader2 className="w-4 h-4 animate-spin" /> : <Send className="w-4 h-4" />}
            {submitting ? t('submitting') : t('submitTicket')}
          </button>
        </form>

        <div className="xl:col-span-2 card p-5">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-white font-semibold">{t('ticketInbox')}</h2>
            {isAdmin && (
              <span className="badge badge-info flex items-center gap-1">
                <ShieldCheck className="w-3 h-3" />
                {t('adminActionsEnabled')}
              </span>
            )}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-3 mb-4 text-sm">
            <div className="bg-slate-900 border border-slate-800 rounded-lg p-3 text-slate-300">{t('openStatus')}: {grouped.open.length}</div>
            <div className="bg-slate-900 border border-slate-800 rounded-lg p-3 text-slate-300">{t('inProgress')}: {grouped.inProgress.length}</div>
            <div className="bg-slate-900 border border-slate-800 rounded-lg p-3 text-slate-300">{t('resolvedStatus')}: {grouped.resolved.length}</div>
          </div>

          {loading ? (
            <div className="flex items-center justify-center py-12">
              <Loader2 className="w-5 h-5 text-emerald-400 animate-spin" />
              <span className="ml-3 text-slate-400 text-sm">{t('loadingTickets')}</span>
            </div>
          ) : tickets.length === 0 ? (
            <div className="text-center py-12 text-slate-500 text-sm">{t('noTicketsYet')}</div>
          ) : (
            <div className="space-y-3">
              {tickets.map((ticket) => (
                <div key={ticket.id} className="bg-slate-900 border border-slate-800 rounded-xl p-4">
                  <div className="flex items-center justify-between gap-3">
                    <div>
                      <p className="text-white font-medium">{ticket.subject}</p>
                      <p className="text-sm text-slate-400 mt-0.5 line-clamp-1">{ticket.description}</p>
                      <p className="text-xs text-slate-500 mt-1">{new Date(ticket.createdAt).toLocaleDateString()} · {ticket.priority}</p>
                    </div>
                    <div className="flex items-center gap-2">
                      <span className={`badge ${statusBadge(ticket.status)}`}>
                        {ticket.status.replace('_', ' ')}
                      </span>
                      {isAdmin && ticket.status !== 'RESOLVED' && ticket.status !== 'CLOSED' && (
                        <button type="button" onClick={() => advanceStatus(ticket)} className="btn-secondary py-2 px-3 text-xs">
                          {t('advance')}
                        </button>
                      )}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

import { useEffect, useState, useCallback } from 'react'
import { useTranslation } from 'react-i18next'
import {
  getDonations,
  updateDonationStatus,
  markAsDelivered,
  getUserProfile,
  updateUserProfile,
  getCompletedTrips,
  toggleAvailability,
  type Donation,
  type User,
} from '../../services/api'
import { socketService } from '../../services/socket'
import {
  CheckCircle2, MapPin, X, ChevronLeft, ChevronRight,
  Image as ImageIcon, Navigation, Truck, Package, Award,
  ToggleLeft, ToggleRight, Car, Bike,
  Star, TrendingUp, AlertTriangle, Zap, Router,
} from 'lucide-react'
import { toast } from 'sonner'

// ─── Helpers ────────────────────────────────────────────────────────────────

const VEHICLE_ICONS: Record<string, string> = {
  bike: '🏍️', car: '🚗', van: '🚐', bicycle: '🚲', walk: '🚶',
}
const FOOD_EMOJI: Record<string, string> = {
  cooked: '🍛', raw: '🥬', packaged: '📦', fruits: '🍎', bakery: '🥖', dairy: '🥛',
}

function getTimeRemaining(expiryTime: Date) {
  const remaining = new Date(expiryTime).getTime() - Date.now()
  const hours = Math.floor(remaining / (1000 * 60 * 60))
  const minutes = Math.floor((remaining % (1000 * 60 * 60)) / (1000 * 60))
  return { hours, minutes, urgent: hours < 3, expired: remaining <= 0 }
}

function openGoogleMaps(address: string, lat?: number, lng?: number) {
  const dest = lat && lng ? `${lat},${lng}` : encodeURIComponent(address)
  window.open(`https://www.google.com/maps/dir/?api=1&destination=${dest}`, '_blank')
}

// ─── Sub-components ──────────────────────────────────────────────────────────

function StatCard({ icon, label, value, accent }: {
  icon: React.ReactNode; label: string; value: string | number; accent: string
}) {
  return (
    <div className="bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-xl p-3 sm:p-4 flex items-center gap-3 sm:gap-4 overflow-hidden">
      <div className={`w-9 h-9 sm:w-11 sm:h-11 rounded-lg flex items-center justify-center shrink-0 ${accent}`}>
        {icon}
      </div>
      <div className="min-w-0">
        <p className="text-xl sm:text-2xl font-bold text-gray-900 dark:text-white truncate">{value}</p>
        <p className="text-xs text-gray-500 dark:text-slate-500 mt-0.5 truncate">{label}</p>
      </div>
    </div>
  )
}

// ─── Availability Toggle ──────────────────────────────────────────────────────

function AvailabilityToggle({ isAvailable, onToggle, loading, t }: {
  isAvailable: boolean; onToggle: () => void; loading: boolean; t: (key: string) => string
}) {
  return (
    <button
      onClick={onToggle}
      disabled={loading}
      className={`flex items-center gap-3 px-5 py-2.5 rounded-xl border font-medium text-sm transition-all duration-200 ${isAvailable
        ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-400 hover:bg-emerald-500/20'
        : 'bg-gray-100 dark:bg-slate-800 border-gray-300 dark:border-slate-700 text-gray-500 dark:text-slate-400 hover:bg-gray-200 dark:hover:bg-slate-700'
        }`}
    >
      {loading ? (
        <span className="w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin" />
      ) : isAvailable ? (
        <ToggleRight className="w-5 h-5" />
      ) : (
        <ToggleLeft className="w-5 h-5" />
      )}
      {isAvailable ? t('availableForPickups') : t('unavailable')}
      <span className={`w-2 h-2 rounded-full ${isAvailable ? 'bg-emerald-400 animate-pulse' : 'bg-gray-400 dark:bg-slate-600'}`} />
    </button>
  )
}

// ─── Vehicle Profile Card ─────────────────────────────────────────────────────

function VehicleProfile({ user, onSave, t }: { user: User; onSave: (data: { vehicleType?: string; vehicleNumber?: string }) => Promise<void>; t: (key: string) => string }) {
  const [editing, setEditing] = useState(false)
  const [vehicleType, setVehicleType] = useState(user.vehicleType || '')
  const [vehicleNumber, setVehicleNumber] = useState(user.vehicleNumber || '')
  const [saving, setSaving] = useState(false)

  const vehicles = [
    { value: 'bike', label: t('bike'), icon: '🏍️' },
    { value: 'car', label: t('car'), icon: '🚗' },
    { value: 'van', label: t('van'), icon: '🚐' },
    { value: 'bicycle', label: t('bicycle'), icon: '🚲' },
    { value: 'walk', label: t('onFoot'), icon: '🚶' },
  ]

  const handleSave = async () => {
    setSaving(true)
    try {
      await onSave({ vehicleType, vehicleNumber })
      setEditing(false)
      toast.success(t('vehicleUpdated'))
    } catch {
      toast.error(t('vehicleSaveFailed'))
    } finally {
      setSaving(false)
    }
  }

  return (
    <div className="bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-xl p-4 sm:p-5">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2 min-w-0">
          <Car className="w-4 h-4 text-purple-400 shrink-0" />
          <h3 className="font-medium text-gray-900 dark:text-white text-sm truncate">{t('vehicleDetails')}</h3>
        </div>
        {!editing && (
          <button
            onClick={() => setEditing(true)}
            className="text-xs text-gray-500 dark:text-slate-400 hover:text-gray-900 dark:hover:text-white border border-gray-300 dark:border-slate-700 rounded-md px-2.5 py-1 hover:border-gray-400 dark:hover:border-slate-600 transition-colors"
          >
            {t('edit')}
          </button>
        )}
      </div>

      {editing ? (
        <div className="space-y-3">
          <div>
            <label className="text-xs text-gray-500 dark:text-slate-500 mb-1.5 block">{t('vehicleType')}</label>
            <div className="grid grid-cols-3 sm:grid-cols-5 gap-1.5">
              {vehicles.map(v => (
                <button
                  key={v.value}
                  onClick={() => setVehicleType(v.value)}
                  className={`flex flex-col items-center gap-1 p-2 rounded-lg border text-xs transition-all ${vehicleType === v.value
                    ? 'border-purple-500 bg-purple-500/10 text-purple-300'
                    : 'border-gray-300 dark:border-slate-700 bg-gray-50 dark:bg-slate-800 text-gray-500 dark:text-slate-400 hover:border-gray-400 dark:hover:border-slate-600'
                    }`}
                >
                  <span className="text-lg">{v.icon}</span>
                  <span className="truncate w-full text-center">{v.label}</span>
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="text-xs text-gray-500 dark:text-slate-500 mb-1.5 block">
              {t('vehicleNumber')} <span className="text-gray-400 dark:text-slate-600">({t('optional')})</span>
            </label>
            <input
              value={vehicleNumber}
              onChange={e => setVehicleNumber(e.target.value)}
              placeholder="e.g. TN 09 AB 1234"
              className="w-full bg-gray-50 dark:bg-slate-800 border border-gray-300 dark:border-slate-700 rounded-lg px-3 py-2 text-sm text-gray-900 dark:text-white placeholder-gray-400 dark:placeholder-slate-600 focus:outline-none focus:border-purple-500"
            />
          </div>

          <div className="flex gap-2 pt-1">
            <button
              onClick={handleSave}
              disabled={saving}
              className="flex-1 py-2 bg-purple-600 hover:bg-purple-500 text-white rounded-lg text-sm font-medium transition-colors"
            >
              {saving ? t('saving') : t('save')}
            </button>
            <button
              onClick={() => setEditing(false)}
              className="px-4 py-2 bg-gray-100 dark:bg-slate-800 hover:bg-gray-200 dark:hover:bg-slate-700 text-gray-700 dark:text-slate-300 rounded-lg text-sm transition-colors"
            >
              {t('cancel')}
            </button>
          </div>
        </div>
      ) : (
        <div className="flex items-center gap-4">
          {user.vehicleType ? (
            <>
              <span className="text-3xl">{VEHICLE_ICONS[user.vehicleType] || '🚗'}</span>
              <div>
                <p className="text-gray-900 dark:text-white font-medium capitalize">{user.vehicleType}</p>
                {user.vehicleNumber && (
                  <p className="text-gray-500 dark:text-slate-500 text-sm mt-0.5">{user.vehicleNumber}</p>
                )}
              </div>
            </>
          ) : (
            <p className="text-gray-500 dark:text-slate-500 text-sm">{t('noVehicleAdded')}</p>
          )}
        </div>
      )}
    </div>
  )
}

// ─── Task Card ────────────────────────────────────────────────────────────────

function TaskCard({
  donation,
  processingId,
  onPickup,
  onDelivery,
  onView,
  t,
}: {
  donation: Donation
  processingId: string | null
  onPickup: (id: string) => void
  onDelivery: (id: string) => void
  onView: (d: Donation) => void
  t: (key: string) => string
}) {
  const timeLeft = getTimeRemaining(donation.expiryTime)
  const isProcessing = processingId === donation.id

  return (
    <div className="p-4 hover:bg-gray-50 dark:hover:bg-slate-800/30 transition-colors">
      <div className="flex flex-col sm:flex-row sm:items-start gap-3 sm:gap-4">
        {/* Top row: icon + info */}
        <div className="flex items-start gap-3 sm:gap-4 flex-1 min-w-0">
          {/* Food icon */}
          <div className={`w-10 h-10 sm:w-11 sm:h-11 rounded-lg flex items-center justify-center text-lg sm:text-xl shrink-0 ${donation.status === 'PICKED_UP' ? 'bg-amber-500/10' : 'bg-emerald-500/10'
            }`}>
            {FOOD_EMOJI[donation.foodType] || '🍱'}
          </div>

          {/* Info */}
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-2 mb-0.5 flex-wrap">
              <p className="font-medium text-gray-900 dark:text-white truncate max-w-[180px] sm:max-w-none">{donation.name}</p>
              <span className={`shrink-0 text-xs px-1.5 py-0.5 rounded font-medium ${donation.status === 'PICKED_UP'
                ? 'bg-amber-500/10 text-amber-400'
                : 'bg-blue-500/10 text-blue-400'
                }`}>
                {donation.status === 'PICKED_UP' ? t('enRoute') : t('awaitingPickup')}
              </span>
            </div>

            <p className="text-sm text-gray-500 dark:text-slate-500 truncate">
              {donation.quantity} {donation.unit} • {donation.donorName}
            </p>

            {donation.location?.address && (
              <div className="flex items-center gap-1 mt-1">
                <MapPin className="w-3 h-3 text-gray-400 dark:text-slate-600 shrink-0" />
                <p className="text-xs text-gray-400 dark:text-slate-600 truncate">{donation.location.address}</p>
              </div>
            )}

            {timeLeft.urgent && !timeLeft.expired && (
              <div className="flex items-center gap-1 mt-1.5">
                <AlertTriangle className="w-3 h-3 text-red-400" />
                <span className="text-xs text-red-400 font-medium">
                  {t('expiresIn')} {timeLeft.hours}h {timeLeft.minutes}m
                </span>
              </div>
            )}
          </div>
        </div>

        {/* Actions */}
        <div className="flex flex-row sm:flex-col gap-1.5 shrink-0 flex-wrap">
          <button
            onClick={() => onView(donation)}
            className="px-3 py-1.5 rounded-md text-xs font-medium bg-gray-100 dark:bg-slate-800 text-gray-700 dark:text-slate-300 hover:bg-gray-200 dark:hover:bg-slate-700 transition-colors border border-gray-300 dark:border-slate-700"
          >
            {t('details')}
          </button>

          <button
            onClick={() => openGoogleMaps(donation.location?.address || '', donation.location?.lat, donation.location?.lng)}
            className="px-3 py-1.5 rounded-md text-xs font-medium bg-gray-100 dark:bg-slate-800 text-gray-700 dark:text-slate-300 hover:bg-gray-200 dark:hover:bg-slate-700 transition-colors border border-gray-300 dark:border-slate-700 flex items-center gap-1"
          >
            <Navigation className="w-3 h-3" /> {t('directions')}
          </button>

          {donation.status === 'CLAIMED' && (
            <button
              onClick={() => onPickup(donation.id)}
              disabled={isProcessing}
              className="px-3 py-1.5 rounded-md text-xs font-medium bg-emerald-600 hover:bg-emerald-500 text-white transition-colors"
            >
              {isProcessing ? '…' : `✓ ${t('pickedUp')}`}
            </button>
          )}

          {donation.status === 'PICKED_UP' && (
            <button
              onClick={() => onDelivery(donation.id)}
              disabled={isProcessing}
              className="px-3 py-1.5 rounded-md text-xs font-medium bg-purple-600 hover:bg-purple-500 text-white transition-colors"
            >
              {isProcessing ? '…' : `✓ ${t('delivered')}`}
            </button>
          )}
        </div>
      </div>
    </div>
  )
}

// ─── Completed Trips Tab ─────────────────────────────────────────────────────

function CompletedTrips({ userId, t }: { userId: string; t: (key: string) => string }) {
  const [trips, setTrips] = useState<Donation[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    getCompletedTrips(userId)
      .then(setTrips)
      .catch(() => setTrips([]))
      .finally(() => setLoading(false))
  }, [userId])

  if (loading) return <div className="p-8 text-center text-gray-500 dark:text-slate-500 text-sm">{t('loading')}</div>

  if (trips.length === 0) {
    return (
      <div className="p-10 text-center">
        <div className="w-14 h-14 rounded-full bg-gray-100 dark:bg-slate-800 flex items-center justify-center mx-auto mb-3">
          <Router className="w-6 h-6 text-gray-400 dark:text-slate-600" />
        </div>
        <p className="text-gray-500 dark:text-slate-500 text-sm">{t('noCompletedTrips')}</p>
        <p className="text-gray-400 dark:text-slate-600 text-xs mt-1">{t('completeFirstDelivery')}</p>
      </div>
    )
  }

  return (
    <div className="divide-y divide-gray-200 dark:divide-slate-800">
      {trips.map(trip => (
        <div key={trip.id} className="p-4 hover:bg-gray-50 dark:hover:bg-slate-800/20 transition-colors">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-lg bg-purple-500/10 flex items-center justify-center text-lg">
              {FOOD_EMOJI[trip.foodType] || '🍱'}
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-gray-900 dark:text-white font-medium text-sm truncate">{trip.name}</p>
              <p className="text-gray-500 dark:text-slate-500 text-xs">{trip.quantity} {trip.unit} • {trip.donorName}</p>
            </div>
            <div className="text-right shrink-0">
              <span className="text-xs px-2 py-0.5 bg-emerald-500/10 text-emerald-400 rounded-full font-medium">
                ✓ {t('delivered')}
              </span>
              {(trip as unknown as { deliveredAt?: string }).deliveredAt && (
                <p className="text-xs text-gray-400 dark:text-slate-600 mt-1">
                  {new Date((trip as unknown as { deliveredAt?: string }).deliveredAt as string).toLocaleDateString()}
                </p>
              )}
            </div>
          </div>
        </div>
      ))}
    </div>
  )
}

// ─── Detail Modal ─────────────────────────────────────────────────────────────

function DetailModal({
  donation,
  processingId,
  onPickup,
  onDelivery,
  onClose,
  t,
}: {
  donation: Donation
  processingId: string | null
  onPickup: (id: string) => void
  onDelivery: (id: string) => void
  onClose: () => void
  t: (key: string) => string
}) {
  const [imgIndex, setImgIndex] = useState(0)
  const isProcessing = processingId === donation.id

  return (
    <div className="fixed inset-0 z-[2000] flex items-center justify-center p-4 bg-black/30 dark:bg-slate-950/85 backdrop-blur-sm">
      <div className="bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-xl w-full max-w-lg max-h-[90vh] overflow-y-auto shadow-2xl">
        {/* Header */}
        <div className="flex items-center justify-between p-5 border-b border-gray-200 dark:border-slate-800">
          <div>
            <h3 className="text-lg font-semibold text-gray-900 dark:text-white">{donation.name}</h3>
            <p className="text-sm text-gray-500 dark:text-slate-500 mt-0.5">
              {donation.quantity} {donation.unit} • {donation.foodType}
            </p>
          </div>
          <button onClick={onClose} className="p-1.5 hover:bg-gray-100 dark:hover:bg-slate-800 rounded-lg text-gray-500 dark:text-slate-400 transition-colors">
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* Image */}
        <div className="relative w-full h-48 bg-gray-50 dark:bg-slate-950">
          {donation.imageUrls?.length > 0 ? (
            <>
              <img src={donation.imageUrls[imgIndex]} alt={donation.name} className="w-full h-full object-cover" />
              {donation.imageUrls.length > 1 && (
                <>
                  <button onClick={() => setImgIndex(p => (p - 1 + donation.imageUrls.length) % donation.imageUrls.length)}
                    className="absolute left-2 top-1/2 -translate-y-1/2 bg-black/50 hover:bg-black/70 text-white p-1.5 rounded-full">
                    <ChevronLeft className="w-4 h-4" />
                  </button>
                  <button onClick={() => setImgIndex(p => (p + 1) % donation.imageUrls.length)}
                    className="absolute right-2 top-1/2 -translate-y-1/2 bg-black/50 hover:bg-black/70 text-white p-1.5 rounded-full">
                    <ChevronRight className="w-4 h-4" />
                  </button>
                  <span className="absolute bottom-2 right-2 bg-black/60 text-white text-xs px-2 py-0.5 rounded">
                    {imgIndex + 1}/{donation.imageUrls.length}
                  </span>
                </>
              )}
            </>
          ) : (
            <div className="flex flex-col items-center justify-center h-full text-gray-400 dark:text-slate-700">
              <ImageIcon className="w-10 h-10 mb-2" />
              <span className="text-sm">{t('noImage')}</span>
            </div>
          )}
        </div>

        {/* Info Grid */}
        <div className="p-5 space-y-4">
          {/* Status badge */}
          <div className="flex items-center gap-2">
            <span className={`text-xs px-2.5 py-1 rounded-full font-medium ${donation.status === 'PICKED_UP'
              ? 'bg-amber-500/10 text-amber-400 border border-amber-500/20'
              : 'bg-blue-500/10 text-blue-400 border border-blue-500/20'
              }`}>
              {donation.status === 'PICKED_UP' ? `🚗 ${t('enRouteToNGO')}` : `📦 ${t('readyForPickup')}`}
            </span>
          </div>

          {/* Pickup address */}
          <div className="bg-gray-50 dark:bg-slate-800/50 rounded-lg p-3.5 space-y-2">
            <p className="text-xs font-medium text-gray-500 dark:text-slate-400 uppercase tracking-wide">{t('pickupLocation')}</p>
            <div className="flex items-start gap-2">
              <MapPin className="w-4 h-4 text-emerald-400 mt-0.5 shrink-0" />
              <p className="text-sm text-gray-900 dark:text-white">{donation.location?.address || t('addressNotAvailable')}</p>
            </div>
            <button
              onClick={() => openGoogleMaps(donation.location?.address || '', donation.location?.lat, donation.location?.lng)}
              className="w-full mt-1 flex items-center justify-center gap-2 py-2 bg-emerald-500/10 hover:bg-emerald-500/20 text-emerald-400 border border-emerald-500/20 rounded-lg text-sm font-medium transition-colors"
            >
              <Navigation className="w-4 h-4" />
              {t('getDirectionsToDonor')}
            </button>
          </div>

          {/* Donor */}
          <div className="grid grid-cols-2 gap-3">
            <div className="bg-gray-50 dark:bg-slate-800/50 rounded-lg p-3">
              <p className="text-xs text-gray-500 dark:text-slate-500 mb-1">{t('donor')}</p>
              <p className="text-sm text-gray-900 dark:text-white font-medium">{donation.donorName}</p>
            </div>
            <div className="bg-gray-50 dark:bg-slate-800/50 rounded-lg p-3">
              <p className="text-xs text-gray-500 dark:text-slate-500 mb-1">{t('expiry')}</p>
              <p className="text-sm text-gray-900 dark:text-white font-medium">
                {new Date(donation.expiryTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </p>
            </div>
          </div>

          {/* Description */}
          {donation.description && (
            <div className="bg-gray-50 dark:bg-slate-800/50 rounded-lg p-3">
              <p className="text-xs text-gray-500 dark:text-slate-500 mb-1">{t('notes')}</p>
              <p className="text-sm text-gray-700 dark:text-slate-300">{donation.description}</p>
            </div>
          )}

          {/* Action buttons */}
          <div className="flex gap-3 pt-1">
            {donation.status === 'CLAIMED' && (
              <button
                onClick={() => { onPickup(donation.id); onClose() }}
                disabled={isProcessing}
                className="flex-1 flex items-center justify-center gap-2 py-2.5 bg-emerald-600 hover:bg-emerald-500 text-white rounded-lg font-medium transition-colors"
              >
                <Package className="w-4 h-4" />
                {isProcessing ? t('processing') : t('confirmPickup')}
              </button>
            )}
            {donation.status === 'PICKED_UP' && (
              <button
                onClick={() => { onDelivery(donation.id); onClose() }}
                disabled={isProcessing}
                className="flex-1 flex items-center justify-center gap-2 py-2.5 bg-purple-600 hover:bg-purple-500 text-white rounded-lg font-medium transition-colors"
              >
                <CheckCircle2 className="w-4 h-4" />
                {isProcessing ? t('processing') : t('confirmDelivery')}
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  )
}

// ─── Main Component ───────────────────────────────────────────────────────────

export default function VolunteerDashboard() {
  const { t } = useTranslation()
  const [donations, setDonations] = useState<Donation[]>([])
  const [loading, setLoading] = useState(false)
  const [processingId, setProcessingId] = useState<string | null>(null)
  const [selectedDonation, setSelectedDonation] = useState<Donation | null>(null)
  const [profile, setProfile] = useState<User | null>(null)
  const [availabilityLoading, setAvailabilityLoading] = useState(false)
  const [activeTab, setActiveTab] = useState<'tasks' | 'trips'>('tasks')

  const user = JSON.parse(localStorage.getItem('user') || '{}')

  const load = useCallback(async () => {
    setLoading(true)
    try {
      const all = await getDonations({ status: ['CLAIMED', 'PICKED_UP'] })
      setDonations(all.filter((d: Donation) =>
        d.status === 'CLAIMED' || d.status === 'PICKED_UP'
      ))
    } catch {
      // silently fail
    } finally {
      setLoading(false)
    }
  }, [])

  const loadProfile = useCallback(async () => {
    try {
      const p = await getUserProfile()
      setProfile(p)
      localStorage.setItem('user', JSON.stringify({ ...user, isAvailable: p.isAvailable, vehicleType: p.vehicleType, vehicleNumber: p.vehicleNumber }))
    } catch { /* ignore */ }
  }, [])

  useEffect(() => {
    load()
    loadProfile()

    const unsubCreated = socketService.onDonationCreated((data) => {
      toast.info(`🍕 ${t('newDonationNearby')}: ${data.name}`, { duration: 4000 })
    })

    const unsubClaimed = socketService.onDonationClaimed(() => { load() })

    const unsubAssigned = socketService.onVolunteerAssigned((data) => {
      if (data.volunteerId === user.id) {
        toast.success(`🚗 ${t('newAssignment')}: ${data.donationName}`, {
          description: `${t('pickupFrom')}: ${data.donorAddress}`,
          duration: 7000,
        })
        load()
      }
    })

    return () => {
      unsubCreated()
      unsubClaimed()
      unsubAssigned()
    }
  }, [load, loadProfile])

  const handleToggleAvailability = async () => {
    setAvailabilityLoading(true)
    try {
      const current = profile?.isAvailable ?? false
      await toggleAvailability(!current)
      setProfile(p => p ? { ...p, isAvailable: !current } : p)
      toast.success(current ? t('nowUnavailable') : t('nowAvailable'))
    } catch {
      toast.error(t('availabilityUpdateFailed'))
    } finally {
      setAvailabilityLoading(false)
    }
  }

  const handleSaveVehicle = async (data: { vehicleType?: string; vehicleNumber?: string }) => {
    const payload: Record<string, string> = {}
    if (data.vehicleType) payload.vehicleType = data.vehicleType
    if (data.vehicleNumber) payload.vehicleNumber = data.vehicleNumber
    await updateUserProfile(payload)
    setProfile(p => p ? { ...p, ...data } : p)
  }

  const handleConfirmPickup = async (id: string) => {
    setProcessingId(id)
    try {
      await updateDonationStatus(id, 'PICKED_UP')
      toast.success(t('pickupConfirmed'))
      await load()
    } catch (error: unknown) {
      const err = error as { message?: string };
      toast.error(err.message || t('pickupFailed'))
    } finally {
      setProcessingId(null)
    }
  }

  const handleConfirmDelivery = async (id: string) => {
    setProcessingId(id)
    try {
      await markAsDelivered(id)
      toast.success(`🎉 ${t('deliveryConfirmed')}`, { duration: 5000 })
      await load()
      await loadProfile()
    } catch (error: unknown) {
      const err = error as { message?: string };
      toast.error(err.message || t('deliveryFailed'))
    } finally {
      setProcessingId(null)
    }
  }

  const activeTasks = donations.filter(d => d.status === 'CLAIMED' || d.status === 'PICKED_UP')
  const pickedUp = donations.filter(d => d.status === 'PICKED_UP').length

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div className="min-w-0">
          <h1 className="text-xl sm:text-2xl font-semibold text-gray-900 dark:text-white truncate">{t('volunteerDashboard')}</h1>
          <p className="text-gray-500 dark:text-slate-500 mt-1 text-sm">{t('managePickupsDeliveries')}</p>
        </div>
        <AvailabilityToggle
          isAvailable={profile?.isAvailable ?? false}
          onToggle={handleToggleAvailability}
          loading={availabilityLoading}
          t={t}
        />
      </div>

      {/* Stats Row */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
        <StatCard
          icon={<Zap className="w-5 h-5 text-yellow-400" />}
          label={t('karmaPoints')}
          value={profile?.karmaPoints ?? user.karmaPoints ?? 0}
          accent="bg-yellow-500/10"
        />
        <StatCard
          icon={<Truck className="w-5 h-5 text-emerald-400" />}
          label={t('activeTasks')}
          value={activeTasks.length}
          accent="bg-emerald-500/10"
        />
        <StatCard
          icon={<Package className="w-5 h-5 text-amber-400" />}
          label={t('enRoute')}
          value={pickedUp}
          accent="bg-amber-500/10"
        />
        <StatCard
          icon={<Award className="w-5 h-5 text-purple-400" />}
          label={t('badges')}
          value={profile?.badges?.length ?? 0}
          accent="bg-purple-500/10"
        />
      </div>

      {/* Badges row */}
      {(profile?.badges?.length ?? 0) > 0 && (
        <div className="flex gap-2 flex-wrap">
          {profile!.badges!.map(badge => (
            <span key={badge} className="text-xs px-2.5 py-1 bg-purple-500/10 text-purple-300 border border-purple-500/20 rounded-full">
              {badge}
            </span>
          ))}
        </div>
      )}

      {/* Vehicle + Tasks layout */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4 sm:gap-5">
        {/* Left: Vehicle profile */}
        <div className="lg:col-span-1 space-y-4">
          <VehicleProfile user={profile ?? user} onSave={handleSaveVehicle} t={t} />

          {/* Quick tip */}
          <div className="bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-xl p-4">
            <div className="flex items-center gap-2 mb-2">
              <Star className="w-4 h-4 text-yellow-400" />
              <p className="text-sm font-medium text-gray-900 dark:text-white">{t('earningKarma')}</p>
            </div>
            <ul className="space-y-1.5">
              {[
                { action: t('confirmPickup'), points: '+10 pts' },
                { action: t('completeDelivery'), points: '+50 pts' },
              ].map(item => (
                <li key={item.action} className="flex justify-between items-center text-xs">
                  <span className="text-gray-500 dark:text-slate-400">{item.action}</span>
                  <span className="text-emerald-400 font-medium">{item.points}</span>
                </li>
              ))}
            </ul>
          </div>
        </div>

        {/* Right: Tasks + trips */}
        <div className="lg:col-span-2 bg-white dark:bg-slate-900 border border-gray-200 dark:border-slate-800 rounded-xl overflow-hidden">
          {/* Tabs */}
          <div className="flex border-b border-gray-200 dark:border-slate-800">
            {[
              { key: 'tasks', label: t('activeTasks'), icon: <Truck className="w-4 h-4" /> },
              { key: 'trips', label: t('completedTrips'), icon: <TrendingUp className="w-4 h-4" /> },
            ].map(tab => (
              <button
                key={tab.key}
                onClick={() => setActiveTab(tab.key as 'tasks' | 'trips')}
                className={`flex items-center gap-2 px-5 py-3.5 text-sm font-medium transition-colors border-b-2 ${activeTab === tab.key
                  ? 'text-gray-900 dark:text-white border-purple-500'
                  : 'text-gray-500 dark:text-slate-500 border-transparent hover:text-gray-700 dark:hover:text-slate-300'
                  }`}
              >
                {tab.icon}
                {tab.label}
                {tab.key === 'tasks' && activeTasks.length > 0 && (
                  <span className="ml-1 w-5 h-5 rounded-full bg-purple-600 text-white text-xs flex items-center justify-center">
                    {activeTasks.length}
                  </span>
                )}
              </button>
            ))}
          </div>

          {activeTab === 'tasks' && (
            <>
              {loading && (
                <div className="p-8 text-center text-gray-500 dark:text-slate-500 text-sm">{t('loading')}</div>
              )}
              {!loading && activeTasks.length === 0 && (
                <div className="p-10 text-center">
                  <div className="w-14 h-14 rounded-full bg-gray-100 dark:bg-slate-800 flex items-center justify-center mx-auto mb-3">
                    <Bike className="w-6 h-6 text-gray-400 dark:text-slate-600" />
                  </div>
                  <p className="text-gray-500 dark:text-slate-400 text-sm font-medium">{t('noActiveTasks')}</p>
                  <p className="text-gray-400 dark:text-slate-600 text-xs mt-1">
                    {profile?.isAvailable
                      ? t('waitingForAssignment')
                      : t('toggleAvailabilityHint')}
                  </p>
                </div>
              )}
              <div className="divide-y divide-gray-200 dark:divide-slate-800">
                {activeTasks.map(donation => (
                  <TaskCard
                    key={donation.id}
                    donation={donation}
                    processingId={processingId}
                    onPickup={handleConfirmPickup}
                    onDelivery={handleConfirmDelivery}
                    onView={d => setSelectedDonation(d)}
                    t={t}
                  />
                ))}
              </div>
            </>
          )}

          {activeTab === 'trips' && <CompletedTrips userId={user.id} t={t} />}
        </div>
      </div>

      {/* Detail Modal */}
      {selectedDonation && (
        <DetailModal
          donation={selectedDonation}
          processingId={processingId}
          onPickup={handleConfirmPickup}
          onDelivery={handleConfirmDelivery}
          onClose={() => setSelectedDonation(null)}
          t={t}
        />
      )}
    </div>
  )
}
